                                <div class="cookies__buttons">
                                    <div class="cookies__button-wrapper">
                                        <button type="button" onclick="acceptCookie();"
                                            class="cookies__accept-button green-gradient-btn button--small">
                                            Accept
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
