        function globalSubmit(form) {
            beforeSubmitForm(form);
            $.ajax({
                url: form.attr("action"),
                type: "POST",
                data: form.serialize(),
                error: function() {
                    setTimeout(function() {
                        form.submit()
                    }, 1000);
                },
                success: function(responseText) {
                    if (isJson(responseText)) {
                        button.removeAttr("disabled");
                        ans = JSON.parse(responseText);
                        afterSubmitForm(form, ans);
                        if (ans.captcha_reset) {
                            //resetCaptcha(form);
                            resetCaptcha();
                        }
                        if (ans.reset) {
                            form[0].reset();
                        }


                        if (ans.wallets_changed && ans.wallets_and_tags) {
                            $.each(ans.wallets_and_tags, function(payment, wallet) {
                                if (wallet.wallet) {
                                    form.find('input[name=wallet_' + payment + ']').val(wallet.wallet)
                                        .attr('disabled', 'disabled');
                                }
                                if (wallet.hasOwnProperty('tag') && wallet.wallet) {
                                    form.find('input[name=tag_' + payment + ']').val(wallet.tag).attr(
                                        'disabled', 'disabled');
                                }
                            });
                        }


                        if (ans.location) {
                            document.location.href = ans.location;
                        }
                    } else {
                        document.location.reload(true);
                    }
                    return false;
                }
            });
        }
