    <script type="text/javascript">
        newTransactionTitle = "New transaction";
        newPaymentNotConfirmed =
            "Your payment of [amount] will be credited to your balance after confirmation by blockchain.";
        newPaymentConfirmed = "Your balance has been successfully topped up by [amount].";

        function mt_verifiedcb(state) {
            if (mainForm) {
                mainForm.find('input[name="mtcaptcha-verifiedtoken"]').remove();
                code = '<input type="hidden" name="mtcaptcha-verifiedtoken" value="' + state.verifiedToken + '">';
                mainForm.append(code);
                $('#modalCaptcha').modal("hide");
                globalSubmit(mainForm);
                mainForm = null;
            }
        }

        function beforeSubmitForm(form, noDisabled = false) {
            form.find('.field-block').find('.field').removeClass('field--error');
            form.find('.field-sign-block').remove();
            button = form.find('button[type="submit"]');
            if (!noDisabled) {
                button.attr("disabled", "disabled");
                if (form.attr('action') == '/balance/') {
                    form.addClass('form-button-block--blured');
                    form.addClass('modal-deposit--overlayed');
                    $('#modalDeposit .modalDepositOverlay').removeClass('d-none');
                    $('#modalDeposit .modal-currency-heading__descr').addClass('modal-currency-heading__descr--blured');
                } else {
                    startProgress();
                }
            }
        }

        function afterSubmitForm(form, ans) {
            if (form.attr('action') == '/balance/') {
                form.removeClass('form-button-block--blured');
                form.removeClass('modal-deposit--overlayed');
                $('#modalDeposit .modalDepositOverlay').addClass('d-none');
                $('#modalDeposit .modal-currency-heading__descr').removeClass('modal-currency-heading__descr--blured');
            } else {
                stopProgress();
            }
            button = form.find('button[type="submit"]');
            button.removeAttr("disabled");

            if (ans.errors) {
                if (getPropertyCount(ans.errors) == 1 && ans.errors.captcha !== undefined) {
                    mainForm = form;
                    $('#modalCaptcha').modal('show');
                } else {

                    focused = false;
                    firstBlock = null;

                    errorsText = '';
                    errorsModalText = '';
                    $.each(ans.errors, function(index, value) {
                        if (index != 'captcha') {
                            input = form.find('[name="' + index + '"]');
                            block = input.closest('.field-block');
                            field = input.closest('.field');
                            field.addClass('field--error');
                            if (input.length) {
                                field.after(
                                    '<div class="field-sign-block"><div class="field-sign field-sign--error">' +
                                    value + '</div></div>');
                            }
                            errorsModalText += '<p>' + value + '</p>';
                        }
                    });
                    if (errorsModalText) {
                        $('#modalError .modalErrorText').html(errorsModalText);
                        $('#modalError').modal('show');
                    }
                }
            }

            if (ans.success && !ans.password_restored) {
                $('#modalSuccess .modalSuccessText').html(ans.success);
                $('#modalSuccess').modal('show');
            }

            if (ans.password_restored || ans.register_success || ans.auth_2fa) {
                if (ans.register_success) {
                    $('.blockHideAfterRegistration').addClass('d-none');
                    $('.blockShowAfterRegistration').removeClass('d-none');
                    if (ans.words) {
                        totalWord = '';
                        words = ans.words;
                        $.each(words, function(index, value) {
                            $('[data-module=user-words] [data-word-key=' + index + ']').html(value);
                            if (index === (words.length - 1)) {
                                totalWord += value;
                            } else {
                                totalWord += value + ' ';
                            }
                        });
                        $('.globalStartBlockRegisterWords').data('clipboard-text', totalWord);
                        $('.globalStartBlockRegisterWords').attr('data-clipboard-text', totalWord);
                    }
                    $('.authorization-block').addClass('authorization-block--recovery-phrase');
                }
                if (ans.auth_2fa) {
                    $('.blockHideFor2FAAuth').addClass('d-none');
                    $('.blockShowFor2FAAuth').removeClass('d-none');
                    $('.blockShowFor2FAAuth form')[0].reset();
                    $('.blockShowFor2FAAuth input[name="code"]').val(ans.code);
                    window.scrollTo(0, 0);
                }
                ans.location = null;
            } else if (ans.words) {
                totalWord = '';
                words = ans.words;
                $.each(words, function(index, value) {
                    $('[data-module=user-words] [data-word-key=' + index + ']').html(value);
                    if (index === (words.length - 1)) {
                        totalWord += value;
                    } else {
                        totalWord += value + ' ';
                    }
                });
                $('#modalRecoveryPhrase').find('.modalRecoveryPhraseWords').data('clipboard-text', totalWord);
                $('#modalRecoveryPhrase').find('.modalRecoveryPhraseWords').attr('data-clipboard-text', totalWord);
                $('#modalRecoveryPhrase').modal('show');
            }

            if (ans.password_restored) {
                $('.blockHideAfterPasswordRestored').addClass('d-none');
                $('.blockShowAfterPasswordRestored').removeClass('d-none');
                $('.blockShowAfterPasswordRestored form')[0].reset();
                if (ans.secret) {
                    $('.blockPasswordRecoverySecretCode').addClass('d-none');
                    $('.blockShowAfterPasswordRestored input[name="secret"]').val(ans.secret);
                } else {
                    $('.blockPasswordRecoverySecretCode').removeClass('d-none');
                }
                window.scrollTo(0, 0);
            }

            if (ans.action == 'confirm' && !ans.auth_2fa) {
                beforeSubmitForm($('#modalConfirm-' + ans.confirm_type + ' form'), true);
                $('#modalConfirm-' + ans.confirm_type + ' form')[0].reset();
                $('#modalConfirm-' + ans.confirm_type + ' form input[name="code"]').val(ans.code);
                $('#modalConfirm-' + ans.confirm_type).modal('show');
                ans.location = null;
            }

            processPusher(ans);

            if (ans.action == 'confirmed' && (ans.new_login || ans.new_email || ans.new_phone || ans.new_password || ans
                    .new_pin || ans.words || ans.new_twofa || ans.add_wallet || ans.remove_wallet || ans.new_telegram !==
                    undefined)) {
                $('.modal--confirm').modal('hide');
                ans.location = null;
            }

            if (ans.add_wallet) {
                $('#modalAddWallet').modal('hide');
                $('#modalAddWallet').find('input[name="wallet"]').val('');
                $('#modalAddWallet').find('input[name="tag"]').val('');
                beforeSubmitForm($('#modalAddWallet').find('form'), true);
            }
            if (ans.remove_session) {
                if (!ans.location) {
                    setActiveModule('settings');
                }
                $('#modalEndSession').modal('hide');
            }

            if (ans.deposit_address !== undefined) {
                currencyInfo = globalCurrencies[ans.deposit_address.currency];
                paymentInfo = globalPayments[ans.deposit_address.payment];
                $('#modalDeposit').find('.modalDepositAddressWT').removeClass('d-none');
                mask = $('#modalDeposit').find('.modalDepositAddressMessage').find('.system-message__text').data('text');
                mask = mask.replace('[currency]', currencyInfo['currency'].toUpperCase());
                mask = mask.replace('[network]', paymentInfo['data']['network']);
                $('#modalDeposit').find('.modalDepositAddressMessage').find('.system-message__text').html(mask);
                $('#modalDeposit').find('.modalDepositAddressMessage').removeClass('d-none');
                $('#modalDeposit').find('.modalDepositAddressTitle').removeClass('d-none');

                $('#modalDeposit').find('.modalDepositF').addClass('d-none');
                $('#modalDeposit').find('.modalDepositTitleSelect').addClass('d-none');
                $('#modalDeposit').find('.modalDepositDescOne').addClass('d-none');
                $('#modalDeposit').find('.modalDepositTitleOne').addClass('d-none');

                if (ans.deposit_address.address) {
                    paymentInfo = globalPayments[ans.deposit_address.payment];

                    $('#modalDeposit').find('.modalDepositAddressTitle').find('.currency-icon').attr('class',
                        'currency-icon');
                    $('#modalDeposit').find('.modalDepositAddressTitle').find('.currency-icon').addClass('currency-icon--' +
                        currencyInfo['config']['data']['icon']);
                    currencyIconSrc = $('#modalDeposit').find('.modalDepositAddressTitle').find('.currency-icon img').data(
                        'src');
                    $('#modalDeposit').find('.modalDepositAddressTitle').find('.currency-icon img').attr('src',
                        currencyIconSrc.replace('[icon]', currencyInfo['config']['data']['icon']));
                    $('#modalDeposit').find('.modalDepositAddressTitle').find('.modal-dep-addr-heading__title').html(
                        currencyInfo['title']);

                    $('#modalDeposit').find('.modalDepositAddressWTAddressInput').html(ans.deposit_address.address);
                    $('#modalDeposit').find('.modalDepositAddressWTAddress').find('.copy-link').data('clipboard-text', ans
                        .deposit_address.address);
                    $('#modalDeposit').find('.modalDepositAddressWTAddress').find('.copy-link').attr('data-clipboard-text',
                        ans.deposit_address.address);

                    $('#modalDeposit').find('.modalDepositAddressTitleNetwork').html(paymentInfo['data']['network']);
                }
                if (ans.deposit_address.tag) {
                    $('#modalDeposit').find('.modalDepositAddressWTTagInput').html(ans.deposit_address.tag);
                    $('#modalDeposit').find('.modalDepositAddressWTTag').find('.copy-link').data('clipboard-text', ans
                        .deposit_address.tag);
                    $('#modalDeposit').find('.modalDepositAddressWTTag').find('.copy-link').attr('data-clipboard-text', ans
                        .deposit_address.tag);

                    $('#modalDeposit').find('.modalDepositAddressWTTag').removeClass('d-none');
                    if (paymentInfo.tag_is_memo) {
                        $('#modalDeposit').find('.modalDepositAddressWTTagTitle').html($('#modalDeposit').find(
                            '.modalDepositAddressWTTagTitle').data('placeholder-memo'));
                    } else {
                        $('#modalDeposit').find('.modalDepositAddressWTTagTitle').html($('#modalDeposit').find(
                            '.modalDepositAddressWTTagTitle').data('placeholder-tag'));
                    }
                } else {
                    $('#modalDeposit').find('.modalDepositAddressWTTagInput').html('');
                    $('#modalDeposit').find('.modalDepositAddressWTTag').addClass('d-none');
                }
            }
            if (ans.add_amount_to_deposit) {
                $('#modalStakingAdd').modal('hide');
            }
            if (ans.release_deposit) {
                $('#modalStakingRelease').modal('hide');
            }
            if (ans.add_promo_code) {
                $('#modalCustomReferralCode').modal('hide');
            }
            if (ans.change_cashback) {
                $('#modalCashback').modal('hide');
            }
            if (ans.add_col_to_loan) {
                $('#modalLoanCol').modal('hide');
            }
            if (ans.pay_loan) {
                $('#optimaLoanRepay').modal('hide');
            }
            if (ans.task_sended) {
                $('#modalTask').modal('hide');
            }
            if (ans.tasks !== undefined) {
                processTasks(ans.tasks);
            }
        }

        function setActivePartnerLevel(userActivePartnerLevel) {
            userActivePartnerLevel = parseInt(userActivePartnerLevel);
            $('.globalAccountPartnersActiveLevelTitle').html('Optima ' + (userActivePartnerLevel + 1));
            $('.globalAccountPartnersNextLevelTitle').html('Optima ' + (userActivePartnerLevel + 2));
            lines = globalAffiliate.by_plan[userActivePartnerLevel];
            nextLines = globalAffiliate.by_plan[userActivePartnerLevel + 1];
            bonuses = globalAffiliate['career_bonuses']['bonuses'];
            $('.globalAccountPartnersNextLevelBonus').html(bonuses[userActivePartnerLevel + 1]['bonus'] + ' USDT');
            i = 1;
            while (i <= 7) {
                $('.globalAccountPartnersActiveLevelL' + i).find('.affiliate-programm-step__line').removeClass(
                    'affiliate-programm-step__line--filled');
                $('.globalAccountPartnersActiveLevelL' + i).find('.affiliate-programm-step').removeClass(
                    'affiliate-programm-step--current');
                $('.globalAccountPartnersActiveLevelL' + i + 'Percent').html('0%');
                $('.globalAccountPartnersNextLevelL' + i).find('.affiliate-programm-step__line').removeClass(
                    'affiliate-programm-step__line--filled');
                $('.globalAccountPartnersNextLevelL' + i).find('.affiliate-programm-step').removeClass(
                    'affiliate-programm-step--current');
                $('.globalAccountPartnersNextLevelL' + i + 'Percent').html('0%');
                i++;
            }
            $.each(lines['percents_by_our_earning'], function(index, value) {
                i = index + 1;
                $('.globalAccountPartnersActiveLevelL' + i).find('.affiliate-programm-step').addClass(
                    'affiliate-programm-step--current');
                $('.globalAccountPartnersActiveLevelL' + i).find('.affiliate-programm-step__line').addClass(
                    'affiliate-programm-step__line--filled');
                $('.globalAccountPartnersActiveLevelL' + i + 'Percent').html(value + '%');
            })
            $.each(nextLines['percents_by_our_earning'], function(index, value) {
                i = index + 1;
                $('.globalAccountPartnersNextLevelL' + i).find('.affiliate-programm-step').addClass(
                    'affiliate-programm-step--current');
                $('.globalAccountPartnersNextLevelL' + i).find('.affiliate-programm-step__line').addClass(
                    'affiliate-programm-step__line--filled');
                $('.globalAccountPartnersNextLevelL' + i + 'Percent').html(value + '%');
            })
        }

