            $('#modalEndSession').modal('show');
        }

        function withdrawalFavouriteAddresses(button) {
            form = button.closest('form');
            currency = form.find('select[name=currency]').selectpicker('val');
            startProgress();
            button.attr('disabled', 'disabled');
            apiRequest('/api_wallets/', 'currency=' + currency, false, {
                "button": button,
                "currency": currency
            });
        }

        function initWithdrawalFavouriteAddressesAdd(button) {
            currency = button.data('currency');
            form = $('#modalAddWallet').find('form');
            form.find('select[name=currency]').selectpicker('val', currency);
            currencyInfo = globalCurrencies[currency];
            if (form.find('input[name=payment]').length && form.find('input[name=payments_type]').length) {
                form.find('input[name=payment]').prop('checked', false);
                form.find('input[name=payment]').closest('.formNetworkItemsItem').addClass('d-none');
                currencyInfoPayments = currencyInfo['config'][form.find('input[name=payments_type]').val() + '_payments'];
                checked = false;
                $.each(currencyInfoPayments, function(index, value) {
                    input = form.find('input[name=payment][value=' + index + ']');
                    input.closest('.formNetworkItemsItem').removeClass('d-none');
                    if (!checked) {
                        setPaymentForForm(form, index, form.find('input[name=payments_type]').val());
                        checked = true;
                    }
                })
            }
            $('#modalAddWallet').find('.modal-descr-block').addClass('d-none');
            $('#modalAddWallet').find('select[name=currency]').closest('.field-block').addClass('d-none');
            $('#modalAddWallet').modal('show');
        }

        function initTaskSend(button) {
            modal = $('#modalTask');
            modal.find('.db-task-item-heading-title').html(button.data('title'));
            modal.find('.db-task-item-heading-icon').attr('class', 'db-task-item-heading-icon db-task-item-heading-icon--' +
                button.data('icon'));
            mask = modal.find('.db-task-item-heading-icon img').data('src');
            mask = mask.replace('[icon]', button.data('icon'));
            modal.find('.db-task-item-heading-icon img').attr('src', mask);
            form = modal.find('form');
            form[0].reset();
            form.find('.field-block').addClass('d-none');
            inputs = JSON.parse(button.data('need_inputs'));
            if (inputs) {
                $.each(inputs, function(index2, value2) {
                    form.find('input[name=' + value2 + ']').closest('.field-block').removeClass('d-none');
                })
            }
            form.find('input[name=id]').val(button.data('id'));
            modal.modal('show');
        }

        function apiRequest(action, params = null, fromPagination = false, showParams = null) {
            $.ajax({
                url: action,
                type: "POST",
                data: params,
                error: function() {

                },
                success: function(responseText) {
                    if (isJson(responseText)) {
                        stopProgress();
                        ans = JSON.parse(responseText);
                        if (ans.errors) {
                            errorsText = '';
                            errorsModalText = '';
                            $.each(ans.errors, function(index, value) {
                                if (index != 'captcha') {
                                    errorsModalText += '<p>' + value + '</p>';
                                }
                            });
                            if (errorsModalText) {
                                $('#modalError .modalErrorText').html(errorsModalText);
                                $('#modalError').modal('show');
                            }
                        }
                        if (ans.success) {
                            $('#modalSuccess .modalSuccessText').html(ans.success);
                            $('#modalSuccess').modal('show');
                        }
                        if (ans.send_wallets) {
                            items = ans.send_wallets.items;
                            if (showParams.button) {
                                showParams.button.removeAttr('disabled');
                            }
                            currencyInfo = globalCurrencies[showParams.currency];
                            $('#modalAddressList').data('currency', showParams.currency);
                            $('#modalAddressList').find('.currency-icon').attr('class', 'currency-icon');
                            $('#modalAddressList').find('.currency-icon').addClass('currency-icon--' +
                                currencyInfo['config']['data']['icon']);
                            currencyIconSrc = $('#modalAddressList').find('.currency-icon img').data('src');
                            $('#modalAddressList').find('.currency-icon img').attr('src', currencyIconSrc
                                .replace('[icon]', currencyInfo['config']['data']['icon']));
                            $('#modalAddressList').find('.modal-currency-heading__descr').html(currencyInfo[
                                'title']);
                            $('#modalAddressList').find('.modalAddressListWalletsNotEmptyItems').html('');
                            if (items.length) {
                                selectText = $('#modalAddressList').find(
                                    '.modalAddressListWalletsNotEmptyItems').data('text-select');
                                itemsHtml = '';
                                $.each(ans.send_wallets.items, function(index, value) {
                                    paymentInfo = globalPayments[value.payment];
                                    itemHtml =
                                        '<div class="modal-address-list-item-wrapper modalAddressListWalletsNotEmptyItemsItem"><button type="button" class="modal-address-list-item" onclick="insertFavouriteWallet(\'' +
                                        value.payment + '\',\'' + value.wallet + '\',\'' + value.tag +
                                        '\')"><div class="modal-address-list-item__left"><div class="modal-address-list-item__currency">' +
                                        currencyInfo['title'] +
                                        '</div><div class="modal-address-list-item__address">' + value
                                        .wallet + '</div><div class="modal-address-list-item__tag">';
                                    if (value.tag) {
                                        itemHtml += '[' + value.tag + ']';
                                    }
                                    itemHtml +=
                                        '</div><div class="modal-address-list-item__network-block"><div class="modal-address-list-item__network">' +
                                        paymentInfo['data']['network'] +
                                        '</div></div></div> <div class="modal-address-list-item__right"><div class="modal-address-list-item__status-block"><div class="modal-address-list-item__status">' +
                                        selectText + '</div></div></div></button></div>';
                                    itemsHtml += itemHtml;
                                })
                                $('#modalAddressList').find('.modalAddressListWalletsNotEmptyItems').html(
                                    itemsHtml);
                                $('#modalAddressList').find('.modalAddressListWalletsNotEmpty').removeClass(
                                    'd-none');
                                $('#modalAddressList').find('.modalAddressListWalletsEmpty').addClass('d-none');
                            } else {
                                $('#modalAddressList').find('.modalAddressListWalletsNotEmpty').addClass(
                                    'd-none');
                                mask = $('#modalAddressList').find('.favorite-addresses-empty__title').data(
                                    'text');
                                $('#modalAddressList').find('.favorite-addresses-empty__title').html(mask
                                    .replace('[currency]', currencyInfo['currency'].toUpperCase()));
                                $('#modalAddressList').find('.modalAddressListWalletsEmpty').removeClass(
                                    'd-none');
                            }
                            $('#modalAddressList').find('.modalAddressListWalletsEmptyButton').data('currency',
                                showParams.currency);
                            $('#modalAddressList').modal('show');
                        }
                        if (ans.wallets) {
                            items = ans.wallets.items;
                            pagination = ans.wallets.pagination;
                            if (items.length) {
                                $.each(ans.wallets.items, function(index, value) {
                                    paymentInfo = globalPayments[value.payment];
                                    currencyInfo = globalCurrencies[paymentInfo['currency']];
                                    addressNotSlice = value.wallet;
                                    address = value.wallet.slice(0, 5);
                                    address += '...';
                                    address += value.wallet.slice(-5);
                                    if (value.tag != '') {
                                        address += ' [' + value.tag + ']';
                                        addressNotSlice += ' [' + value.tag + ']';
                                    }
                                    item = $('.globalAccountSettingsWalletsNotEmptyTableItemsItem').eq(
                                        index);
                                    item.find('.currency-icon').attr('class', 'currency-icon');
                                    item.find('.currency-icon').addClass('currency-icon--' +
                                        currencyInfo['config']['data']['icon']);
                                    currencyIconSrc = item.find('.currency-icon img').data('src');
                                    item.find('.currency-icon img').attr('src', currencyIconSrc.replace(
                                        '[icon]', currencyInfo['config']['data']['icon']));
                                    item.find('.currency-item__title').html(currencyInfo['title']);
                                    item.find('.currency-item__abbr').html(currencyInfo['currency']);

                                    item.find('.fa-t-i-network').html(paymentInfo['data']['network']);
                                    item.find('.fa-t-i-address__title').html(address);
                                    item.find('.copy-icon-button').data('clipboard-text',
                                        addressNotSlice);
                                    item.find('.copy-icon-button').attr('data-clipboard-text',
                                        addressNotSlice);

                                    item.find('.fa-t-i-date').html(value.date_create_date_text);
                                    item.find('input[name=id]').val(value.id);
                                    item.removeClass('d-none');
                                })
                                $('.globalAccountSettingsWalletsNotEmpty').removeClass('d-none');
                                $('.globalAccountSettingsWalletsEmpty').addClass('d-none');
                                pagesHtml = '';
                                if (pagination.length) {
                                    $.each(pagination, function(index, value) {
                                        pagesHtml += '<li class="pagination-item ';
                                        if (value.page == ans.wallets.page)
                                            pagesHtml += 'active';
                                        pagesHtml += '"><button onclick="';
                                        if (value.page != ans.wallets.page)
                                            pagesHtml +=
                                            'readyForLoadModule(\'wallets\');apiRequest(\'/api_wallets/\',\'page=' +
                                            value.page + '\',true);';
                                        pagesHtml += 'return false;" class="pagination-link">' + value
                                            .page + '</a></li>';
                                    })
                                }
                                $('.globalAccountSettingsWalletsNotEmptyPages').html(pagesHtml);
                                if (fromPagination) {
                                    scrollToElement($('.globalAccountSettingsWalletsNotEmptyTable'));
                                }
                            } else {
                                $('.globalAccountSettingsWalletsNotEmpty').addClass('d-none');
                                $('.globalAccountSettingsWalletsEmpty').removeClass('d-none');
                            }
                        }
                        if (ans.sessions) {
                            items = ans.sessions.items;
                            pagination = ans.sessions.pagination;
                            if (items.length) {
                                $.each(ans.sessions.items, function(index, value) {
                                    item = $('.globalAccountSettingsSessionsNotEmptyTableItemsItem').eq(
                                        index);
                                    if (value.active) {
                                        item.addClass('active');
                                        item.find('.act-session-t-i-active-status').removeClass(
                                            'd-none');
                                    } else {
                                        item.removeClass('active');
                                        item.find('.act-session-t-i-active-status').addClass('d-none');
                                    }
                                    item.find('.act-session-t-i-device__title').html(value.platform);
                                    item.find('.act-session-t-i-device__browser').html(value.browser);
                                    item.find('.act-session-t-i-ip').html(value.ip);
                                    locationText = '';
                                    if (value.country_name) {
                                        locationText += value.country_name;
                                        if (value.city) {
                                            locationText += ', ';
                                        }
                                    }
                                    if (value.city) {
                                        locationText += value.city;
                                    }
                                    item.find('.act-session-t-i-location').html(locationText);
                                    item.find('.act-session-t-i-remove-button').attr('onclick',
                                        'endSession(' + value.id + ');return false;');
                                    item.removeClass('d-none');
                                })
                                pagesHtml = '';
                                if (pagination.length) {
                                    $.each(pagination, function(index, value) {
                                        pagesHtml += '<li class="pagination-item ';
                                        if (value.page == ans.sessions.page)
                                            pagesHtml += 'active';
                                        pagesHtml += '"><button onclick="';
                                        if (value.page != ans.sessions.page)
                                            pagesHtml +=
                                            'readyForLoadModule(\'sessions\');apiRequest(\'/api_sessions/\',\'page=' +
                                            value.page + '\',true);';
                                        pagesHtml += 'return false;" class="pagination-link">' + value
                                            .page + '</a></li>';
                                    })
                                }
                                $('.globalAccountSettingsSessionsNotEmptyPages').html(pagesHtml);
                                if (fromPagination) {
                                    scrollToElement($('.globalAccountSettingsSessionsNotEmptyTable'));
                                }
                            }
                        }
                        if (ans.transactions) {
                            items = ans.transactions.items;
                            pagination = ans.transactions.pagination;
                            filter = ans.transactions.filter;
                            reloadDynamic = false;
                            if (items.length) {
                                $.each(ans.transactions.items, function(index, value) {
                                    mEq = index + 1;
                                    transactionModal = $('#modalTransaction-' + mEq);
                                    currencyInfo = globalCurrencies[value.currency];
                                    item = $('.globalAccountTransactionsNotEmptyTableItemsItem').eq(
                                        index);

                                    item.attr('class',
                                        'db-transaction-table-item globalAccountTransactionsNotEmptyTableItemsItem'
                                    );

                                    item.addClass('db-transaction-table-item--' + value.new_class);
                                    item.find('.db-transaction-t-i-type').attr('class',
                                        'db-transaction-t-i-type');
                                    item.find('.db-transaction-t-i-type').addClass(
                                        'db-transaction-t-i-type--' + value.new_class);

                                    transactionModal.find('.modal-transaction-param-type').attr('class',
                                        'modal-transaction-param-type');
                                    transactionModal.find('.modal-transaction-param-type').addClass(
                                        'modal-transaction-param-type--' + value.new_class);

                                    item.find('.db-transaction-t-i-type__hash-block').addClass(
                                        'd-none');
                                    item.find('.db-transaction-t-i-type__descr').addClass('d-none');
                                    if (value.description !== undefined) {
                                        item.find('.db-transaction-t-i-type__descr').removeClass(
                                            'd-none').html(value.description);
                                    }

                                    item.find('.currency-icon').attr('class', 'currency-icon');
                                    item.find('.currency-icon').addClass('currency-icon--' +
                                        currencyInfo['config']['data']['icon']);
                                    currencyIconSrc = item.find('.currency-icon img').data('src');
                                    item.find('.currency-icon img').attr('src', currencyIconSrc.replace(
                                        '[icon]', currencyInfo['config']['data']['icon']));
                                    item.find('.currency-item__title').html(currencyInfo['title']);

                                    transactionModal.find('.currency-icon').attr('class',
                                        'currency-icon');
                                    transactionModal.find('.currency-icon').addClass('currency-icon--' +
                                        currencyInfo['config']['data']['icon']);
                                    currencyIconSrc = transactionModal.find('.currency-icon img').data(
                                        'src');
                                    transactionModal.find('.currency-icon img').attr('src',
                                        currencyIconSrc.replace('[icon]', currencyInfo['config'][
                                            'data'
                                        ]['icon']));
                                    transactionModal.find('.currency-item__title').html(currencyInfo[
                                        'title']);



                                    item.find('.db-transaction-t-i-status').addClass('d-none');
                                    transactionModal.find('.modal-transaction-status').addClass(
                                        'd-none');
                                    transactionModal.find('.modal-transaction-icon').addClass('d-none');

                                    if (value.status == 'error') {
                                        item.find('.db-transaction-t-i-status--canceled').removeClass(
                                            'd-none');
                                        transactionModal.find('.modal-transaction-status--canceled')
                                            .removeClass('d-none');
                                        transactionModal.find('.modal-transaction-icon--canceled')
                                            .removeClass('d-none');
                                    } else if (value.status == 'success') {
                                        item.find('.db-transaction-t-i-status--completed').removeClass(
                                            'd-none');
                                        transactionModal.find('.modal-transaction-status--completed')
                                            .removeClass('d-none');
                                        transactionModal.find('.modal-transaction-icon--completed')
                                            .removeClass('d-none');
                                    } else {
                                        item.find('.db-transaction-t-i-status--pending').removeClass(
                                            'd-none');
                                        transactionModal.find('.modal-transaction-status--pending')
                                            .removeClass('d-none');
                                        transactionModal.find('.modal-transaction-icon--pending')
                                            .removeClass('d-none');
                                    }
                                    item.find('.db-transaction-t-i-date').html(value.date_create_text);
                                    transactionModal.find('.db-transaction-t-i-date').html(value
                                        .date_create_text);

                                    currencyRound = currencyInfo['round'];
                                    start = currencyRound;
                                    amountMinutelyFinded = false;
                                    if (value.minutely_array) {
                                        if (BigNumber(value.minutely_array.amount).isGreaterThan(0)) {
                                            amountMinutelyFinded = true;
                                        }
                                    }
                                    if (BigNumber(value.amount).isGreaterThan(0) ||
                                        amountMinutelyFinded) {
                                        while (start <= 12) {
                                            if (BigNumber(BigNumber(value.amount).toFixed(start))
                                                .isEqualTo(0)) {
                                                currencyRound = start;
                                            } else {
                                                currencyRound = start;
                                                start = 13;
                                            }
                                            start++;
                                        }
                                    }

                                    item.find('.db-transaction-t-i-type__title').html(value.title);
                                    transactionModal.find('.modal-transaction-param-type__title').html(
                                        value.title);

                                    item.find('.db-transaction-t-i-amount').data('round',
                                        currencyRound);
                                    item.find('.db-transaction-t-i-amount').data('transaction-id', value
                                        .id);
                                    item.find('.db-transaction-t-i-amount').data('value', value.amount);
                                    item.find('.db-transaction-t-i-amount').data('plus-minutely', '0');
                                    item.find('.db-transaction-t-i-amount').data('active', '');
                                    item.find('.db-transaction-t-i-amount').html(convert(parseFloat(
                                        BigNumber(value.amount).toFixed(currencyRound))));

                                    transactionModal.find('.modalTransactionAmount').data('round',
                                        currencyRound);
                                    transactionModal.find('.modalTransactionAmount').data(
                                        'transaction-id', value.id);
                                    transactionModal.find('.modalTransactionAmount').data('value', value
                                        .amount);
                                    transactionModal.find('.modalTransactionAmount').data(
                                        'plus-minutely', '0');
                                    transactionModal.find('.modalTransactionAmount').data('active', '');
                                    transactionModal.find('.modalTransactionAmount').html(convert(
                                            parseFloat(BigNumber(value.amount).toFixed(
                                                currencyRound))) + ' ' + currencyInfo['currency']
                                        .toUpperCase());

                                    if (value.minutely_array) {
                                        if (BigNumber(value.minutely_array.amount).isGreaterThan(0)) {
                                            realAmount = getStartRealAmount(value.amount, value
                                                .minutely_array.amount);
                                            item.find('.db-transaction-t-i-amount').data('value',
                                                realAmount);
                                            item.find('.db-transaction-t-i-amount').data(
                                                'plus-minutely', value.minutely_array.amount);
                                            item.find('.db-transaction-t-i-amount').data('active', '1');
                                            mask = item.find('.db-transaction-t-i-amount').data('mask');
                                            item.find('.db-transaction-t-i-amount').html(mask.replace(
                                                '[amount]', convert(parseFloat(BigNumber(
                                                    realAmount).toFixed(currencyRound)))));

                                            transactionModal.find('.modalTransactionAmount').data(
                                                'value', realAmount);
                                            transactionModal.find('.modalTransactionAmount').data(
                                                'plus-minutely', value.minutely_array.amount);
                                            transactionModal.find('.modalTransactionAmount').data(
                                                'active', '1');
                                            mask = '[amount] ' + currencyInfo['currency'].toUpperCase();
                                            transactionModal.find('.modalTransactionAmount').data(
                                                'mask', mask);
                                            transactionModal.find('.modalTransactionAmount').attr(
                                                'data-mask', mask);
                                            transactionModal.find('.modalTransactionAmount').html(mask
                                                .replace('[amount]', convert(parseFloat(BigNumber(
                                                    realAmount).toFixed(currencyRound)))));

                                            reloadDynamic = true;
                                        }
                                    }


                                    transactionModal.find('.modalTransactionInfo').addClass('d-none');
                                    if (value.upline_uid !== undefined) {
                                        transactionModal.find(
                                            '.modalTransactionInfo[data-param=upline_uid] .modalTransactionInfoValue'
