                                        } else {
                                            fixAvailable = true;
                                        }
                                        if (min === null) {
                                            min = rate;
                                        }
                                        if (max === null) {
                                            max = rate;
                                        }
                                        if (BigNumber(rate).isLessThan(min)) {
                                            min = rate;
                                        }
                                        if (BigNumber(rate).isGreaterThan(max)) {
