        function processTasks(tasks) {
            $.each(tasks, function(index, value) {
                item = $('.globalAccountTasksItemsItem').eq(index);
                item.attr('task-id', value.id);
                item.find('.db-task-item-heading-icon').attr('class',
                    'db-task-item-heading-icon db-task-item-heading-icon--' + value.icon);
                mask = item.find('.db-task-item-heading-icon img').data('src');
                mask = mask.replace('[icon]', value.icon);
                item.find('.db-task-item-heading-icon img').attr('src', mask);
                item.find('.db-task-item-heading-title').html(value.title);
                valueDesc = value.description;
                item.find('.db-task-item__descr').html(valueDesc.replace('@optima_updates',
                    '<a href="https://t.me/optima_updates" target="_blank">@optima_updates</a>'));
                reqHtml = '';
                $.each(value.reqs, function(index2, value2) {
                    reqHtml +=
                        '<div class="db-task-item__benefit-wrapper"><div class="db-task-item__benefit">' +
                        value2 + '</div></div>';
                })
                item.find('.db-task-item__benefits').html(reqHtml);
                item.find('.globalAccountTasksItemsItemLimitOne').addClass('d-none');
                item.find('.globalAccountTasksItemsItemLimitEvery').addClass('d-none');
                if (value.every_seconds > 0) {
                    days = value.every_seconds / 86400;
                    mask = item.find('.globalAccountTasksItemsItemLimitEvery').data('text');
                    mask = mask.replace('[days]', days);
                    item.find('.globalAccountTasksItemsItemLimitEvery').html(mask);
                    item.find('.globalAccountTasksItemsItemLimitEvery').removeClass('d-none');
                } else {
                    item.find('.globalAccountTasksItemsItemLimitOne').removeClass('d-none');
                }
                if (value.check_time > 0) {
                    hours = value.check_time / 3600;
                    mask = item.find('.globalAccountTasksItemsItemVerification').data('text');
                    mask = mask.replace('[hours]', hours);
                    item.find('.globalAccountTasksItemsItemVerification').html(mask);
                    item.find('.globalAccountTasksItemsItemVerification').removeClass('d-none');
                }
                item.find('.globalAccountTasksItemsItemBonus').addClass('d-none');
                item.find('.globalAccountTasksItemsItemBonus1stBonus').addClass('d-none');
                item.find('.globalAccountTasksItemsItemBonus2ndBonus').addClass('d-none');
                item.find('.globalAccountTasksItemsItemBonus .text--white').addClass('d-none');
                item.find('.globalAccountTasksItemsItemBonus1stBonus .text--white').addClass('d-none');
                item.find('.globalAccountTasksItemsItemBonus2ndBonus .text--white').addClass('d-none');
                if (value.max_first_reward != value.max_seconds_reward && value.max_seconds_reward != '') {
                    item.find('.globalAccountTasksItemsItemBonus1stBonus').find('.text--green').html(value
                        .max_first_reward);
                    item.find('.globalAccountTasksItemsItemBonus1stBonus').removeClass('d-none');
                    item.find('.globalAccountTasksItemsItemBonus2ndBonus').find('.text--green').html(value
                        .max_seconds_reward);
                    item.find('.globalAccountTasksItemsItemBonus2ndBonus').removeClass('d-none');
                    firstReward = value.max_first_reward;
                    secondReward = value.max_seconds_reward;
                    if (firstReward.indexOf('USDT') >= 0) {
                        item.find('.globalAccountTasksItemsItemBonus1stBonus .text--white').removeClass('d-none');
                    }
                    if (secondReward.indexOf('USDT') >= 0) {
                        item.find('.globalAccountTasksItemsItemBonus2ndBonus .text--white').removeClass('d-none');
                    }
                } else {
                    item.find('.globalAccountTasksItemsItemBonus').find('.text--green').html(value
                        .max_first_reward);
                    item.find('.globalAccountTasksItemsItemBonus').removeClass('d-none');
                    firstReward = value.max_first_reward;
                    if (firstReward.indexOf('USDT') >= 0) {
                        item.find('.globalAccountTasksItemsItemBonus .text--white').removeClass('d-none');
                    }
                }
                item.find('.globalAccountTasksItemsItemAffiliateLevel').addClass('d-none');
                if (value.partner_level > 0) {
                    mask = item.find('.globalAccountTasksItemsItemAffiliateLevel').find('.text--white').data(
                        'text');
                    partnerLevel = parseInt(value.partner_level) + 1;
                    item.find('.globalAccountTasksItemsItemAffiliateLevel').find('.text--white').html('Optima ' +
                        partnerLevel + ' ' + mask);
                    item.find('.globalAccountTasksItemsItemAffiliateLevel').removeClass('d-none');
                }
                item.find('.globalAccountTasksItemsItemWaiting').addClass('d-none');
                item.find('.globalAccountTasksItemsItemSend').addClass('d-none');
                item.find('.globalAccountTasksItemsItemSendNotAuth').addClass('d-none');
                item.find('.globalAccountTasksItemsItemNotAvailable').addClass('d-none');
                item.find('.globalAccountTasksItemsItemNeedTime').addClass('d-none');
                item.find('.optimaTimer').data('value', 0);
                item.find('.optimaTimer').data('active', '');
                mask = item.find('.globalAccountTasksItemsItemSend').find('iconed-btn__text').data('text');
                item.find('.globalAccountTasksItemsItemSend').find('iconed-btn__text').html(mask);
                button = item.find('.globalAccountTasksItemsItemSend button');
                button.data('need_inputs', value.need_inputs);
                button.data('title', value.title);
                button.data('icon', value.icon);
                button.data('id', value.id);
                if (value['status'] == 'not_available') {
                    item.find('.globalAccountTasksItemsItemNotAvailable').removeClass('d-none');
                } else if (value.status == 'need_time') {
                    item.find('.optimaTimer').data('value', value.seconds_left);
                    item.find('.optimaTimer').data('active', 1);
                    item.find('.globalAccountTasksItemsItemNeedTime').removeClass('d-none');
                } else if (value.status == 'waiting') {
                    item.find('.globalAccountTasksItemsItemWaiting').find('input[name=id]').val(value.id);
                    item.find('.globalAccountTasksItemsItemWaiting').removeClass('d-none');
                } else {
                    if (value.authed) {
                        item.find('.globalAccountTasksItemsItemSend').removeClass('d-none');
                    } else {
                        item.find('.globalAccountTasksItemsItemSendNotAuth').removeClass('d-none');
                    }
                }
                item.removeClass('d-none');
            })
        }

