            item.find('.globalAccountPartnersNotEmptyTableItemsItemLoans').removeClass('db-partner-t-i-loans--positive');
            if (BigNumber(value.loans_fixed_earn_me_usd).isGreaterThan(0)) {
                item.find('.globalAccountPartnersNotEmptyTableItemsItemLoans').addClass('db-partner-t-i-loans--positive');
                isActive = true;
                totalEarnings = BigNumber(totalEarnings).plus(value.loans_fixed_earn_me_usd);
            }
            if (BigNumber(value.loans_flexible_earn_me_usd).isGreaterThan(0)) {
                item.find('.globalAccountPartnersNotEmptyTableItemsItemLoans').addClass('db-partner-t-i-loans--positive');
                isActive = true;
                totalEarnings = BigNumber(totalEarnings).plus(value.loans_flexible_earn_me_usd);
            }

