                value.loans_fixed_earn_me_usd).plus(value.loans_flexible_earn_me_usd).toFixed(8))));
            item.find('.globalAccountPartnersNotEmptyTableItemsItemLoansFix').html('$' + convert(parseFloat(BigNumber(value
                .loans_fixed_earn_me_usd).toFixed(8))));
            item.find('.globalAccountPartnersNotEmptyTableItemsItemLoansFlex').html('$' + convert(parseFloat(BigNumber(value
                .loans_flexible_earn_me_usd).toFixed(8))));


            item.find('.globalAccountPartnersNotEmptyTableItemsItemExchangeAmount').html('$' + convert(parseFloat(BigNumber(
                value.exchange_earn_me_usd).toFixed(8))));
            text = item.find('.globalAccountPartnersNotEmptyTableItemsItemExchangeVolume').data('text-volume');
            item.find('.globalAccountPartnersNotEmptyTableItemsItemExchangeVolume').html(text + ': $' + convert(parseFloat(
                BigNumber(value.exchange_me_usd).toFixed(8))));


            if (BigNumber(value.me_usd).isGreaterThan(0)) {
                isActive = true;
                totalEarnings = BigNumber(totalEarnings).plus(value.me_usd);
                item.find('.globalAccountPartnersNotEmptyTableItemsItemStaking').addClass(
                    'db-partner-t-i-ai-staking--active');
            }

            item.find('.globalAccountPartnersNotEmptyTableItemsItemTotal').data('value', convert(parseFloat(BigNumber(
                totalEarnings).toFixed(8))));
            item.find('.globalAccountPartnersNotEmptyTableItemsItemTotal').data('plus-minutely', '0');
            item.find('.globalAccountPartnersNotEmptyTableItemsItemTotal').data('active', '');
            item.find('.globalAccountPartnersNotEmptyTableItemsItemTotal').html('$' + convert(parseFloat(BigNumber(
                totalEarnings).toFixed(8))));

            if (partnerModal) {
                partnerModal.find('.modalPartnerTotalAmount').data('value', convert(parseFloat(BigNumber(totalEarnings)
                    .toFixed(8))));
                partnerModal.find('.modalPartnerTotalAmount').data('plus-minutely', '0');
                partnerModal.find('.modalPartnerTotalAmount').data('active', '');
                partnerModal.find('.modalPartnerTotalAmount').html('$' + convert(parseFloat(BigNumber(totalEarnings)
                    .toFixed(8))));

                $.each(value.total_me, function(index, value2) {
                    partnerModal.find('.modalPartnerAmount[data-currency=' + index + ']').data('value', value2);
                    partnerModal.find('.modalPartnerAmount[data-currency=' + index + ']').data('plus-minutely',
                        '0');
                    partnerModal.find('.modalPartnerAmount[data-currency=' + index + ']').data('active', '');
                    mask = partnerModal.find('.modalPartnerAmount[data-currency=' + index + ']').data('mask');
                    partnerModal.find('.modalPartnerAmount[data-currency=' + index + ']').html(mask.replace(
                        '[amount]', convert(parseFloat(BigNumber(value2).toFixed(8)))));
                    if (value.minutely_array) {
                        if (value.minutely_array.me) {
                            if (BigNumber(value.minutely_array.me[index]).isGreaterThan(0)) {
                                realAmount = getStartRealAmount(value2, value.minutely_array.me[index]);
                                partnerModal.find('.modalPartnerAmount[data-currency=' + index + ']').data('value',
                                    realAmount);
                                partnerModal.find('.modalPartnerAmount[data-currency=' + index + ']').data(
                                    'plus-minutely', value.minutely_array.me[index]);
                                partnerModal.find('.modalPartnerAmount[data-currency=' + index + ']').data('active',
                                    '1');
                                mask = partnerModal.find('.modalPartnerAmount[data-currency=' + index + ']').data(
                                    'mask');
                                partnerModal.find('.modalPartnerAmount[data-currency=' + index + ']').html(mask
                                    .replace('[amount]', convert(parseFloat(BigNumber(realAmount).toFixed(8)))));
                            }
                        }
                    }
                })

            }

            item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingAmount').data('value', convert(parseFloat(
                BigNumber(value.me_usd).toFixed(8))));
            item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingAmount').data('plus-minutely', '0');
            item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingAmount').data('active', '');
            item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingAmount').html('$' + convert(parseFloat(BigNumber(
                value.me_usd).toFixed(8))));



            if (value.minutely_array) {
                if (BigNumber(value.minutely_array.me_usd).isGreaterThan(0)) {
                    item.find('.globalAccountPartnersNotEmptyTableItemsItemStaking').addClass(
                        'db-partner-t-i-ai-staking--active');
                    isActive = true;

                    realAmount = getStartRealAmount(totalEarnings, value.minutely_array.me_usd);
                    item.find('.globalAccountPartnersNotEmptyTableItemsItemTotal').data('value', realAmount);
                    item.find('.globalAccountPartnersNotEmptyTableItemsItemTotal').data('plus-minutely', value
                        .minutely_array.me_usd);
                    item.find('.globalAccountPartnersNotEmptyTableItemsItemTotal').data('active', '1');
                    mask = item.find('.globalAccountPartnersNotEmptyTableItemsItemTotal').data('mask');
                    item.find('.globalAccountPartnersNotEmptyTableItemsItemTotal').html(mask.replace('[amount]', convert(
                        parseFloat(BigNumber(realAmount).toFixed(8)))));

                    if (partnerModal) {
                        partnerModal.find('.modalPartnerTotalAmount').data('value', realAmount);
                        partnerModal.find('.modalPartnerTotalAmount').data('plus-minutely', value.minutely_array.me_usd);
                        partnerModal.find('.modalPartnerTotalAmount').data('active', '1');
                        mask = partnerModal.find('.modalPartnerTotalAmount').data('mask');
                        partnerModal.find('.modalPartnerTotalAmount').html(mask.replace('[amount]', convert(parseFloat(
                            BigNumber(realAmount).toFixed(8)))));
                    }

                    realAmount = getStartRealAmount(value.me_usd, value.minutely_array.me_usd);
                    item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingAmount').data('value', realAmount);
                    item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingAmount').data('plus-minutely', value
                        .minutely_array.me_usd);
                    item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingAmount').data('active', '1');
                    mask = item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingAmount').data('mask');
                    item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingAmount').html(mask.replace('[amount]',
                        convert(parseFloat(BigNumber(realAmount).toFixed(8)))));
                }
            }

            text = item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingActive').data('text-active');
            item.find('.globalAccountPartnersNotEmptyTableItemsItemStakingActive').html(text + ': $' + convert(parseFloat(
                BigNumber(value.total_active_deposits_usd).toFixed(8))));


            if (isActive) {
                item.find('.globalAccountPartnersNotEmptyTableItemsItemStatusActive').removeClass('d-none');
            } else {
                item.find('.globalAccountPartnersNotEmptyTableItemsItemStatusNotActive').removeClass('d-none');
            }
        }

        function updateDepositBlock(item, value) {
            currencyInfo = globalCurrencies[value.currency];
            planInfo = globalPlans[value.plan];
            item.find('.currency-icon').attr('class', 'currency-icon');
            item.find('.currency-icon').addClass('currency-icon--' + currencyInfo['config']['data']['icon']);
            currencyIconSrc = item.find('.currency-icon img').data('src');
            item.find('.currency-icon img').attr('src', currencyIconSrc.replace('[icon]', currencyInfo['config']['data'][
                'icon'
            ]));
            item.find('.ai-staking-item__currency').html(currencyInfo['title'] + ' (' + currencyInfo['currency']
                .toUpperCase() + ')');
            item.find('.globalAccountStakingNotEmptyItemsItemAmount').html(value.amount_text);

            rs = value.random_string;
            item.find('.globalAccountStakingNotEmptyItemsItemRS').html('#' + rs.toUpperCase());

            item.find('.ai-staking-item__status').addClass('d-none');
            if (value.date_end > 0) {
                item.find('.ai-staking-item__status--closed').removeClass('d-none');
            } else if (BigNumber(value.amount).isEqualTo(0) && value.date_hold > 0) {
                item.find('.ai-staking-item__status--hold').removeClass('d-none');
            } else {
                item.find('.ai-staking-item__status--active').removeClass('d-none');
            }

            if (value.plan == 1) {
                type = 'algorithmic';
                strategy = 'algo';
            } else if (value.plan >= 4 && value.plan <= 9) {
                type = 'short-term';
                strategy = 'short';
            } else if (value.plan >= 10 && value.plan <= 15) {
                type = 'medium-term';
                strategy = 'medium';
            } else if (value.plan >= 16 && value.plan <= 21) {
                type = 'long-term';
                strategy = 'long';
            }

            item.find('.ai-staking-item__type').attr('class', 'ai-staking-item__type');
            item.find('.ai-staking-item__type').addClass('ai-staking-item__type--' + type);
            planText = item.find('.ai-staking-item__type__title').data('text-' + type);
            if (planInfo['return_any_time_array'][0]['min_seconds']) {
                planText += ' · ' + (planInfo['return_any_time_array'][0]['min_seconds'] / 86400) + ' ' + item.find(
                    '.ai-staking-item__type__title').data('text-days');
            }
            item.find('.ai-staking-item__type__title').html(planText);

            item.find('.globalAccountStakingNotEmptyItemsItemAvgDaily').html('0%');
            item.find('.globalAccountStakingNotEmptyItemsItemAvgMonthly').html('0%');
            item.find('.globalAccountStakingNotEmptyItemsItemAvgYearly').html('0%');

            item.find('.globalAccountStakingNotEmptyItemsItemFees').html(getFeeByPlanAndPercentKey(value.plan, value
                .percent_id) + '%');



            if (parseInt(value.date_end) > 0) {
                dateEnd = parseInt(value.date_end);
            } else {
                dateEnd = parseInt(value.timestamp);
            }
            dateDiff = dateEnd - parseInt(value.date_create);
            days = BigNumber(dateDiff).dividedBy('86400');

            avgDaily = BigNumber(BigNumber(value.percent).dividedBy(days)).toFixed(12);
            avgMonthly = BigNumber(avgDaily).multipliedBy(30);
            avgYearly = BigNumber(avgDaily).multipliedBy(365);
            item.find('.globalAccountStakingNotEmptyItemsItemAvgDaily').html(convert(parseFloat(BigNumber(avgDaily).toFixed(
                2))) + '%');
            item.find('.globalAccountStakingNotEmptyItemsItemAvgMonthly').html(convert(parseFloat(BigNumber(avgMonthly)
                .toFixed(2))) + '%');
            item.find('.globalAccountStakingNotEmptyItemsItemAvgYearly').html(convert(parseFloat(BigNumber(avgYearly)
                .toFixed(2))) + '%');

            item.find('.globalAccountStakingNotEmptyItemsItemCreated').html(value.date_create_text);

            item.find('.globalAccountStakingNotEmptyItemsItemEarning').data('value', value.amount_payed_text);
            item.find('.globalAccountStakingNotEmptyItemsItemEarning').data('plus-minutely', '0');
            item.find('.globalAccountStakingNotEmptyItemsItemEarning').data('active', '');
            item.find('.globalAccountStakingNotEmptyItemsItemEarning').html(value.amount_payed_text);

            if (value.minutely_array) {
                if (value.minutely_array.deposit) {
                    if (BigNumber(value.minutely_array.deposit.amount_payed).isGreaterThan(0)) {
                        realAmount = getStartRealAmount(value.amount_payed, value.minutely_array.deposit.amount_payed);
                        item.find('.globalAccountStakingNotEmptyItemsItemEarning').data('value', realAmount);
                        item.find('.globalAccountStakingNotEmptyItemsItemEarning').data('plus-minutely', value
                            .minutely_array.deposit.amount_payed);
                        item.find('.globalAccountStakingNotEmptyItemsItemEarning').data('active', '1');
                        item.find('.globalAccountStakingNotEmptyItemsItemEarning').data('round', currencyInfo['round']);
                        reloadDynamic = true;
                        mask = item.find('.globalAccountStakingNotEmptyItemsItemEarning').data('mask');
