        function dynamicTimer() {
            $('.optimaTimer').each(function() {
                el = $(this);
                if (el.data('active') == '1') {
                    value = el.data('value');
                    days = Math.floor(value / 86400);
                    hours = Math.floor((value - (days * 86400)) / 3600);
                    minutes = Math.floor((value - (days * 86400) - (hours * 3600)) / 60);
                    seconds = Math.floor((value - (days * 86400) - (hours * 3600) - (minutes * 60)));
                    if (days < "10") {
                        days = "0" + days;
                    }
                    if (hours < "10") {
                        hours = "0" + hours;
                    }
                    if (minutes < "10") {
                        minutes = "0" + minutes;
                    }
                    if (seconds < "10") {
                        seconds = "0" + seconds;
                    }
                    newValue = value - 1;
                    if (newValue < 0)
                        newValue = 0;
                    el.data('value', newValue);
                    showHtml = days + ':' + hours + ':' + minutes + ':' + seconds;
                    el.html(showHtml);
                }
            })
        }

        function dynamicAmount() {
            $('.optimaDynamicAmount').each(function() {
                el = $(this);
                if (el.data('active') == '1') {
                    value = el.data('value');
                    if (el.data('plus-minutely')) {
                        newValue = BigNumber(value).plus(BigNumber(el.data('plus-minutely')).div(60).toFixed(16))
                            .toFixed(16);
                    } else if (el.data('plus')) {
                        newValue = BigNumber(value).plus(el.data('plus')).toFixed(16);
                    } else {
                        newValue = BigNumber(value).plus(0).toFixed(16);
                    }
                    el.data('value', newValue);
                    showValue = convert(parseFloat(BigNumber(newValue).toFixed(el.data('round'))));
                    showHtml = el.data('mask').replace("[amount]", showValue);
                    el.html(showHtml);
                }
            })
        }

        function reloadDynamicAmount() {
            clearInterval(dynamicAmountVar);
            dynamicAmountVar = setInterval(dynamicAmount, 1000);
        }

        function getUsdAmount(currency, amount, round) {
            currencyInfoGetUsdAmount = globalCurrencies[currency];
            if (currencyInfoGetUsdAmount['usd_equal']) {
                newAmount = BigNumber(amount).toFixed(round);
            } else {
                rate = globalRates[currencyInfoGetUsdAmount['currency']];
                newAmount = BigNumber(amount).multipliedBy(rate).toFixed(round);
            }
            return getAmount(newAmount);
        }

        function getStartRealAmount(realValue, plusMinutely) {
            currentTime = Math.floor(Date.now() / 1000);
            currentSecond = BigNumber(currentTime).mod(60);
            if (BigNumber(realValue).isLessThanOrEqualTo('0')) {
                return '0';
            } else if (currentSecond == 0) {
                return realValue;
            } else {
                diff = BigNumber(60 - currentSecond).dividedBy(60);
                diffValue = BigNumber(diff).multipliedBy(plusMinutely);
                newRealValue = BigNumber(realValue).minus(diffValue.toFixed(12));
                if (BigNumber(newRealValue).isLessThan('0')) {
                    newRealValue = '0';
                }
                return newRealValue;
            }
        }

