        function processBalances(balances) {
            totalStakingUsd = 0;
            totalLoansUsd = 0;
            if (balances['total_balance_usd'] !== undefined) {
                totalBalanceUsdIt = $('[data-module="user-balance-usd"]');
                plusAmount = 0;
                if (balances['minutely'] !== undefined) {
                    if (balances['minutely']['stat_plus_usd'] !== undefined) {
                        plusAmount = balances['minutely']['stat_plus_usd'];
                    }
                }
                realAmount = getStartRealAmount(balances['total_balance_usd'], plusAmount);
                totalBalanceUsdIt.data('value', realAmount);
                if (BigNumber(plusAmount).isGreaterThan(0)) {
                    totalBalanceUsdIt.data('active', 1);
                    totalBalanceUsdIt.data('plus-minutely', plusAmount);
                } else {
                    totalBalanceUsdIt.data('active', 0);
                    totalBalanceUsdIt.data('plus-minutely', '0');
                }
                mask = totalBalanceUsdIt.data('mask');
                totalBalanceUsdIt.html(mask.replace('[amount]', convert(parseFloat(BigNumber(realAmount).toFixed(2)))));
            }
            if (balances['real_balances'] !== undefined) {
                $.each(globalCurrencies, function(index) {
                    currencyInfo = globalCurrencies[index];
                    currencyIt = $('[data-module="user-balance"][data-currency="' + index + '"]');
                    currencyItem = currencyIt.find('[data-type="currency"]');
                    plusAmount = 0;
                    if (balances['minutely'] !== undefined) {
                        if (balances['minutely']['plus_' + index] !== undefined) {
                            plusAmount = balances['minutely']['plus_' + index];
                        }
                    }
                    realAmount = getStartRealAmount(balances['real_balances'][index], plusAmount);
                    currencyItem.data('value', realAmount);

                    if (currencyIt.data('page') == 'account' && (BigNumber(plusAmount).isEqualTo(0) ||
                            plusAmount === undefined) && BigNumber(balances['real_balances'][index]).isEqualTo(0)) {
                        currencyItem.closest('.db-asset-t-i-available-block').addClass(
                            'db-asset-t-i-available--empty');
                    } else {
                        currencyItem.closest('.db-asset-t-i-available-block').removeClass(
                            'db-asset-t-i-available--empty');
                    }
                    currencyRound = currencyInfo['round'];
                    start = currencyRound;
                    if (BigNumber(balances['real_balances'][index]).isGreaterThan(0) || BigNumber(plusAmount)
                        .isGreaterThan(0)) {
                        while (start <= 12) {
                            if (BigNumber(BigNumber(balances['real_balances'][index]).toFixed(start)).isEqualTo(
                                    0)) {
                                currencyRound = start;
                            } else {
                                currencyRound = start;
                                start = 13;
                            }
                            start++;
                        }
                    }

                    if (BigNumber(plusAmount).isGreaterThan(0)) {
                        currencyItem.data('active', 1);
                        currencyItem.data('plus-minutely', plusAmount);
                        currencyItem.data('round', currencyRound);
                    } else {
                        currencyItem.data('active', 0);
                        currencyItem.data('plus-minutely', '0');
                    }
                    mask = currencyItem.data('mask');
                    currencyItem.html(mask.replace('[amount]', convert(parseFloat(BigNumber(realAmount).toFixed(
                        currencyInfo['round'])))));


                    currencyItemUsd = currencyIt.find('[data-type="usd"]');
                    if (currencyItemUsd.length) {
                        usdAmount = getUsdAmount(index, realAmount, 12);
                        currencyItemUsd.data('value', usdAmount);
                        mask = currencyItemUsd.data('mask');
                        currencyItemUsd.html(mask.replace('[amount]', convert(parseFloat(BigNumber(usdAmount)
                            .toFixed(2)))));
                        plusAmountUsd = getUsdAmount(index, plusAmount, 12);
                        if (BigNumber(plusAmountUsd).isGreaterThan(0)) {
                            currencyItemUsd.data('active', 1);
                            currencyItemUsd.data('plus-minutely', plusAmountUsd);
                        } else {
                            currencyItemUsd.data('active', 0);
                            currencyItemUsd.data('plus-minutely', '0');
                        }
                    }
                    currencyItStaking = $('[data-module="user-balance-staking"][data-currency="' + index + '"]');
                    if (currencyItStaking.length && balances['stat_active'] !== undefined) {
                        currencyItStaking.find('.db-asset-t-i-loan__borrow').removeClass('d-none');
                        currencyItStaking.find('.db-asset-t-i-stake__amount-wrapper').addClass('d-none');
                        currencyItStaking.find('.db-asset-t-i-stake__status-wrapper').addClass('d-none');

                        stakingAmount = 0;
                        if (balances['stat_active']['deposits'] !== undefined) {
                            if (balances['stat_active']['deposits'][index] !== undefined) {
                                stakingAmount = balances['stat_active']['deposits'][index];
                            }
                        }
                        if (currencyInfo['usd_equal']) {
                            totalStakingUsd = BigNumber(totalStakingUsd).plus(stakingAmount);
                        } else {
                            totalStakingUsd = BigNumber(totalStakingUsd).plus(BigNumber(stakingAmount).multipliedBy(
                                globalRates[currencyInfo['currency']]));
                        }
                        if (BigNumber(stakingAmount).isGreaterThan('0')) {
                            currencyItStaking.find('[data-type=currency]').html(convert(parseFloat(stakingAmount)) +
                                ' ' + currencyInfo['currency'].toUpperCase());
                            currencyItStaking.find('.db-asset-t-i-loan__borrow').addClass('d-none');
                            currencyItStaking.find('.db-asset-t-i-stake__amount-wrapper').removeClass('d-none');
                            currencyItStaking.find('.db-asset-t-i-stake__status-wrapper').removeClass('d-none');
                        }
                        $('[data-module="user-staking-usd"]').html('$' + convert(parseFloat(BigNumber(
                            totalStakingUsd).toFixed(2))));
                    }
                    currencyItLoan = $('[data-module="user-balance-loan"][data-currency="' + index + '"]');
                    if (currencyItLoan.length && balances['stat_active'] !== undefined) {
                        currencyItLoan.find('.db-asset-t-i-loan__borrow').removeClass('d-none');
                        currencyItLoan.find('.db-asset-t-i-loan__amount-wrapper').addClass('d-none');
                        currencyItLoan.find('.db-asset-t-i-loan__status-wrapper').addClass('d-none');

                        loanAmount = 0;
                        if (balances['stat_active']['loans'] !== undefined) {
                            if (balances['stat_active']['loans'][index] !== undefined) {
                                loanAmount = getAmount(balances['stat_active']['loans'][index]);
                            }
                        }

                        if (currencyInfo['usd_equal']) {
                            totalLoansUsd = BigNumber(totalLoansUsd).plus(loanAmount);
                        } else {
                            totalLoansUsd = BigNumber(totalLoansUsd).plus(BigNumber(loanAmount).multipliedBy(
                                globalRates[currencyInfo['currency']]));
                        }
                        if (BigNumber(loanAmount).isGreaterThan('0')) {
                            currencyItLoan.find('[data-type=currency]').html(convert(parseFloat(loanAmount)) + ' ' +
                                currencyInfo['currency'].toUpperCase());
                            currencyItLoan.find('.db-asset-t-i-loan__borrow').addClass('d-none');
                            currencyItLoan.find('.db-asset-t-i-loan__amount-wrapper').removeClass('d-none');
                            currencyItLoan.find('.db-asset-t-i-loan__status-wrapper').removeClass('d-none');
                        }
                        $('[data-module="user-loans-usd"]').html('$' + convert(parseFloat(BigNumber(totalLoansUsd)
                            .toFixed(2))));
                    }
                })
            }
        }

