        function setActiveModule(userActiveModule, moduleParams = null, firstLaunch = false) {
            readyForLoadModule(userActiveModule, moduleParams);
            if (firstLaunch) {
                menuItem = $('[data-module=menu][data-section=' + userActiveModule + ']');
                menuItem.closest('.db-menu-list').find('.db-menu-item').removeClass('active');
                menuItem.closest('.db-menu-item').addClass('active');
            }
            if (userActiveModule == 'wallets') {
                startProgress();
                apiRequest('/api_wallets/', 'page=1');
            }
            if (userActiveModule == 'settings') {
                startProgress();
                apiRequest('/api_sessions/', 'page=1');
            }
            if (userActiveModule == 'transactions') {
                startProgress();
                resetTransactionsFilter($('.globalAccountTransactionsFilterForm'));
                apiRequest('/api_transactions/', 'page=1');
            }
            if (userActiveModule == 'send' && firstLaunch) {
                startProgress();
                apiRequest('/api_balances/', '');
            }
            if (userActiveModule == 'exchange' && firstLaunch) {
                startProgress();
                apiRequest('/api_balances/', '');
            }
            if (userActiveModule == 'account') {
                startProgress();
                apiRequest('/api_news/', '');
            }
            if (userActiveModule == 'staking') {
                startProgress();
                apiRequest('/api_deposits/', '');
            }
            if (userActiveModule == 'stake') {
                startProgress();
                apiRequest('/api_plans/', '');
            }
            if (userActiveModule == 'activity') {
                startProgress();
                strategy = 'algo';
                random_string = '';
                type = '';
                if (moduleParams) {
                    if (moduleParams['type']) {
                        type = moduleParams['type'];
                    }
                    if (moduleParams['strategy']) {
                        strategy = moduleParams['strategy'];
                    }
                    if (moduleParams['random_string']) {
                        random_string = moduleParams['random_string'];
                    }
                }
                apiRequest('/api_trades/', 'strategy=' + strategy + '&random_string=' + random_string + '&type=' + type);
            }
            if (userActiveModule == 'partners') {
                startProgress();
                apiRequest('/api_partners/', '');
            }
            if (userActiveModule == 'loans') {
                startProgress();
                apiRequest('/api_loans/', '');
            }
            if (userActiveModule == 'loan') {
                startProgress();
                apiRequest('/api_loan_rates/', '');
            }
            if (userActiveModule == 'loan_form') {
                newCurrency = null;
                newType = null;
                if (moduleParams) {
                    if (moduleParams['currency']) {
                        newCurrency = moduleParams['currency'];
                    }
                    if (moduleParams['type']) {
                        newType = moduleParams['type'];
                    }
                }
                initLoanForm($('.globalAccountLoansNewForm form'), newCurrency, newType);
            }
            if (userActiveModule == 'tasks') {
                startProgress();
                apiRequest('/api_tasks/', '');
            }
        }

        function resetTransactionsFilter(form) {
            form.find('select').val('');
            form.find('select').selectpicker('destroy');
            form.find('select').selectpicker();
        }

        function getTransactionsFilterValues(form) {
            filterString = '';
            currencyValue = form.find('select[name=currency]').selectpicker('val');
            if (currencyValue && currencyValue != 'all') {
                filterString += '&currency=' + currencyValue;
            }
            typeValue = form.find('select[name=type]').selectpicker('val');
            if (typeValue && typeValue != 'all') {
                filterString += '&type=' + typeValue;
            }
            statusValue = form.find('select[name=status]').selectpicker('val');
            if (statusValue && statusValue != 'all') {
                filterString += '&status=' + statusValue;
            }
            return filterString;
        }

        function insertFavouriteWallet(payment, wallet, tag) {
            $('.globalAccountSendForm input[name=payment]').prop('checked', false);
            $('.globalAccountSendForm input[name=payment][value=' + payment + ']').prop('checked', true);
            $('.globalAccountSendForm input[name=wallet]').val(wallet);
            $('.globalAccountSendForm input[name=tag]').val(tag);
            $('#modalAddressList').modal('hide');
        }

        function getPropertyCount(obj) {
            var count = 0,
                key;

            for (key in obj) {
                if (obj.hasOwnProperty(key)) {
                    count++;
                }
            }

            return count;
        }


        function processPusher(ans) {
            if (ans.new_login) {
                userActiveLogin = ans.new_login;
                setActiveLogin(userActiveLogin);
            }

            if (ans.new_email) {
                userActiveEmail = ans.new_email;
                setActiveEmail(userActiveEmail);
            }

            if (ans.new_phone) {
                userActivePhone = ans.new_phone;
                setActivePhone(userActivePhone);
            }

            if (ans.new_country) {
                userActiveCountry = ans.new_country;
                setActiveCountry(userActiveCountry);
            }

            if (ans.new_password) {
                userActivePassword = ans.new_password;
                setActivePassword(userActivePassword);
            }

            if (ans.new_pin) {
                userActivePIN = ans.new_pin;
                setActivePIN(userActivePIN);
            }

            if (ans.new_telegram !== undefined) {
                setActiveTelegram(ans.new_telegram, ans.new_telegram_username);
            }

            if (ans.new_twofa) {
                userActive2FA = ans.new_twofa;
                setActive2FA(userActive2FA);
                if (ans.new_twofa == 'on') {
                    $('#modalSetup2FA').modal('hide');
                    $('.modalSetup2FAImage').attr('src', '');
                    $('#modalSetup2FA').find('.copy-link').data('clipboard-text', '');
                    $('#modalSetup2FA').find('.copy-link').attr('data-clipboard-text', '');
                    //remove copy code
                }
                if (ans.new_twofa == 'off') {
                    $('.modalSetup2FAImage').attr('src', ans.twofa_image);
                    $('#modalSetup2FA').find('.copy-link').data('clipboard-text', ans.twofa_secret);
                    $('#modalSetup2FA').find('.copy-link').attr('data-clipboard-text', ans.twofa_secret);
                }
            }

            if (ans.add_wallet || ans.remove_wallet) {
                if ($('#modalAddressList').hasClass('show')) {
                    if (ans.add_wallet) {
                        apiRequest('/api_wallets/', 'currency=' + $('#modalAddressList').data('currency'), false, {
                            "currency": $('#modalAddressList').data('currency')
                        });
                    }
                } else {
                    setActiveModule('wallets');
                }
            }

            if (ans.balances) {
                processBalances(ans.balances);
                reloadDynamicAmount();
            }

            if (ans.affiliates) {
                processAffiliates(ans.affiliates);
                reloadDynamicAmount();
            }

            if (ans.deposit_updated) {
                item = $('[deposit-id=' + ans.deposit_updated.id + ']');
                if (item.length) {
                    updateDepositBlock(item, ans.deposit_updated);
                    reloadDynamicAmount();
                }
            }

            if (ans.loan_updated) {
                item = $('[loan-id=' + ans.loan_updated.id + ']');
                if (item.length) {
                    updateLoanBlock(item, ans.loan_updated);
                }
            }

            if (ans.new_partner_level) {
                setActivePartnerLevel(ans.new_partner_level);
            }

            if (ans.new_payment_not_confirmed) {
                mask = customToastWarning.replace('[title]', newTransactionTitle);
                maskHtml = newPaymentNotConfirmed.replace('[amount]', ans.new_payment_not_confirmed.amount_text);
                mask = mask.replace('[html]', maskHtml);
                toastr.warning(mask, '', {
                    html: true
                });
            }

            if (ans.new_payment_confirmed) {
                mask = customToastSuccess.replace('[title]', newTransactionTitle);
                maskHtml = newPaymentConfirmed.replace('[amount]', ans.new_payment_confirmed.amount_text);
                mask = mask.replace('[html]', maskHtml);
                toastr.success(mask, '', {
                    html: true
                });
            }
        }


        function initLangs(block) {
            search = block.find('input[name=search_lang]').val().toLowerCase();
            block.find('.modalLanguageItems .modalLanguageItemsItem').each(function() {
                el = $(this);
                el.removeClass('d-none');
                if (search) {
                    if (el.find('.modalLanguageItemsItemTitle').text().toLowerCase().indexOf(search) < 0 && el.find(
                            '.modalLanguageItemsItemEnglish').text().toLowerCase().indexOf(search) < 0) {
                        el.addClass('d-none');
                    }
                }
            })
        }

        function changeLangLinks(newUrl) {
            $('.changeLangLink').each(function() {
                $(this).attr('href', '/' + $(this).data('lang') + newUrl);
            })
        }

        function setPaymentForForm(form, payment, paymentsType) {
            paymentInfo = globalPayments[payment];
            paymentInput = form.find('input[name=payment][value=' + payment + ']');
            paymentInput = paymentInput.prop('checked', true);
            if (paymentsType == 'withdraw') {
                if (form.find('input[name=wallet]').length) {
                    walletInput = form.find('input[name=wallet]');
                    walletInput.val('');
                    walletPlaceholder = walletInput.data('placeholder').replace('[network]', paymentInfo['data'][
                        'network'
                    ]);
                    walletInput.attr('placeholder', walletPlaceholder);
                }
                if (form.find('input[name=tag]').length) {
                    tagInput = form.find('input[name=tag]');
                    tagInput.val('');
                    if (paymentInfo.tag_is_memo)
                        tagPlaceholder = tagInput.data('placeholder-memo');
                    else
                        tagPlaceholder = tagInput.data('placeholder-tag');
                    tagInput.attr('placeholder', tagPlaceholder);
                    if (paymentInfo['need_tag']) {
                        tagInput.closest('.field-block').removeClass('d-none');
                    } else {
                        tagInput.closest('.field-block').addClass('d-none');
                    }
                }
            }
            if (paymentsType == 'up') {
                if (form.find('.modalDepositFormUniqueNotice').length) {
                    if (paymentInfo['static']) {
                        form.find('.modalDepositFormUniqueNotice').addClass('d-none');
                    } else {
                        form.find('.modalDepositFormUniqueNotice').removeClass('d-none');
                    }
                }
            }
            if (form.attr('action') == '/withdraw/') {
                initSendForm(form);
            }
        }

        function initSendForm(form) {
            amount = getAmount(form.find('input[name=amount]').val());
            currency = form.find('select[name=currency]').selectpicker('val');
            payment = form.find('input[name=payment]:checked').val();

            currencyInfo = globalCurrencies[currency];
            currentCurrency = currencyInfo['currency'];

            form.find('[data-module=user-balance]').addClass('d-none');
            form.find('[data-module=user-balance][data-currency=' + currency + ']').removeClass('d-none');

            res = calcAmountByPayAmount('withdraw', currency, payment, amount);
            form.find('.globalAccountSendFormReceive').html(convert(parseFloat(res.amount)) + ' ' + currentCurrency
                .toUpperCase());
            form.find('.globalAccountSendFormFee').html(convert(parseFloat(res.total_fee)) + ' ' + currentCurrency
                .toUpperCase());
            /*
            minText = form.find('.globalAccountSendFormMin').data('mask');
            minText = minText.replace('[currency]',currentCurrency.toUpperCase());
            minText = minText.replace('[amount]',currencyInfo['config']['withdraw_min']);
            form.find('.globalAccountSendFormMin').html(minText);
            */
        }

        function initStakingForm(form) {
            strategy = form.find('input[name=strategy-radio]:checked').val();
            form.find('.globalAccountStakingFormTermItem').addClass('d-none');
            form.find('.globalAccountStakingFormTerm').hide();
            form.find('input[name=plan]').prop('checked', false);
            form.find('input[name=plan][data-strategy=' + strategy + ']').first().prop('checked', true);
            form.find('input[name=plan][data-strategy=' + strategy + ']').closest('.globalAccountStakingFormTermItem')
                .removeClass('d-none');
            if (strategy != 'algo') {
                form.find('.globalAccountStakingFormTerm').show();
            }
        }

        function initAffiliateForm(form) {
            currency = form.find('select[name=currency]').selectpicker('val');
            currencyInfo = globalCurrencies[currency];
            product = form.find('input[name=product]:checked').val();
            form.find('.globalPageAffiliateProgramFormDuration').addClass('d-none');
            form.find('.globalPageAffiliateProgramFormStrategy').addClass('d-none');
            form.find('.globalPageAffiliateProgramFormTerm').addClass('d-none');
            form.find('.globalPageAffiliateProgramFormColCurrency').addClass('d-none');
            form.find('.globalPageAffiliateProgramFormColAmount').addClass('d-none');
            if (product == 'staking') {
                form.find('.globalPageAffiliateProgramFormStrategy').removeClass('d-none');
                strategy = form.find('input[name=strategy-radio]:checked').val();
                if (strategy != 'algo') {
                    form.find('.globalPageAffiliateProgramFormTerm').removeClass('d-none');
                }
                form.find('.globalPageAffiliateProgramFormTermItem').addClass('d-none');
                form.find('input[name=plan]').prop('checked', false);
                form.find('input[name=plan][data-strategy=' + strategy + ']').first().prop('checked', true);
                form.find('input[name=plan][data-strategy=' + strategy + ']').closest(
                    '.globalPageAffiliateProgramFormTermItem').removeClass('d-none');
            } else if (product == 'exchange') {

            } else if (product == 'loans') {
                form.find('.globalPageAffiliateProgramFormDuration').removeClass('d-none');
                form.find('.globalPageAffiliateProgramFormColCurrency').removeClass('d-none');
                form.find('.globalPageAffiliateProgramFormColAmount').removeClass('d-none');

                currency = form.find('select[name=currency]').selectpicker('val');
                currencyCol = form.find('select[name=currency_col]').selectpicker('val');
                form.find('select[name=currency_col] option').prop('disabled', false);
                if (currencyCol == currency) {
                    firstItem = form.find('select[name=currency_col] option').not(':checked').first();
                    form.find('select[name=currency_col]').selectpicker('val', firstItem.attr('value'));
                    changeAmount(form, 'amount_col', 'old_currency_col', 'currency_col');
                    form.find('input[name=old_currency_col]').val(currency);
                    currencyCol = form.find('select[name=currency_col]').selectpicker('val');
                }
                form.find('select[name=currency_col] option[value=' + currency + ']').prop('disabled', true);
                form.find('select[name=currency_col]').selectpicker('destroy');
                form.find('select[name=currency_col]').selectpicker('render');

                amount = getAmount(form.find('input[name=amount]').val());
                currencyColInfo = globalCurrencies[currencyCol];
                amountUsd = getUsdAmount(currency, amount, 2);
                rate = globalRates[currencyColInfo['currency']];
                newColAmount = BigNumber(BigNumber(amountUsd).multipliedBy('2')).dividedBy(rate).toFixed(currencyColInfo[
                    'round']);
                form.find('input[name=amount_col]').val(convert(parseFloat(BigNumber(newColAmount).toFixed(currencyColInfo[
                    'round']))));
                currencyInfo = globalCurrencies[currency];
                globalLoanRatesCurrency = globalLoanRates[currencyInfo['currency']];
                loanTypes = ['7d', '14d', '30d', '60d', '90d', '180d', 'flexible'];
                type = form.find('input[name=type]:checked').val();
                if (BigNumber(globalLoanRatesCurrency[type]).isEqualTo('0')) {
                    form.find('input[name=type]').prop('checked', false);
                    type = null;
                }
                checked = false;
                $.each(loanTypes, function(index, value) {
                    loanTypeRadio = form.find('input[name=type][value="' + value + '"]');
                    loanTypeRadioItem = loanTypeRadio.closest('.duration-radio-item-wrapper');
                    if (BigNumber(globalLoanRatesCurrency[value]).isGreaterThan(0)) {
                        rate = BigNumber(globalLoanRatesCurrency[value]).multipliedBy('100').toFixed(2);
                        loanTypeRadioItem.find('.min-term-radio__fee').html(rate + '%');
                        loanTypeRadioItem.removeClass('d-none');
                        if (!type && !checked) {
                            loanTypeRadio.prop('checked', true);
                            type = $(this).val();
                            checked = true;
                        }
                    } else {
                        loanTypeRadioItem.addClass('d-none');
                    }
                });
                currencyInfo = globalCurrencies[currency];
                currencyInfoCol = globalCurrencies[currencyCol];
                currentCurrency = currencyInfo['currency'];
                currentCurrencyCol = currencyInfoCol['currency'];

                form.find('.inputAmountCurrency').html(currentCurrency.toUpperCase());
                form.find('.inputAmountCurrencyCol').html(currentCurrencyCol.toUpperCase());

            }
            amountTitle = form.find('.globalPageAffiliateProgramFormAmountTitle').data('text-' + product);
            form.find('.globalPageAffiliateProgramFormAmountTitle').html(amountTitle);
            calcAffiliateForm(form);
        }

        function calcAffiliateForm(form) {
            strategy = form.find('input[name=strategy-radio]:checked').val();
