                        percent).toFixed(4))) + ' %');
                    form.find('.globalPageAffiliateProgramFormCalcEstMonthlyAmount').html('≈' + convert(parseFloat(
                        monthlyReturnAmount)) + ' ' + currencyInfo['currency'].toUpperCase());
