                loanAPR = BigNumber(loanRate).multipliedBy('100').toFixed(2);
                loanRate2 = globalLoanRates[currency]['flexible'];
                loanAPR2 = BigNumber(loanRate2).multipliedBy('100').toFixed(2);
                form.find('.globalPageAffiliateProgramFormCalcEDLIPercent').html(loanAPR + '% APR');
                form.find('.globalPageAffiliateProgramFormCalcOverdueEDLIPercent').html(BigNumber(loanAPR2).multipliedBy(
                    2) + '% APR');
                form.find('.globalPageAffiliateProgramFormCalcReturn').addClass('d-none');
                form.find('.globalPageAffiliateProgramFormCalcEDLI').addClass('d-none');
                form.find('.globalPageAffiliateProgramFormCalcEDLIAmount').html('N/A');
                form.find('.globalPageAffiliateProgramFormCalcOverdueEDLIAmount').html('N/A');
                form.find('.globalPageAffiliateProgramFormCalcReturnAmount').html('N/A');
                amountEDLI = 0;
                if (BigNumber(amount).isGreaterThan(0) && BigNumber(amountCol).isGreaterThan(0)) {
                    if (type == 'flexible') {
                        form.find('.globalPageAffiliateProgramFormCalcEDLI').removeClass('d-none');
                        amountEDLI = BigNumber(amount).multipliedBy(BigNumber(loanRate).dividedBy('365'));
                        amountEDLIAffiliate = BigNumber(amountEDLI).multipliedBy(currentAffiliatePercent).toFixed(
                            currencyInfo['round']);
                        amountEDLI = BigNumber(amountEDLI).toFixed(currencyInfo['round']);
                        form.find('.globalPageAffiliateProgramFormCalcEDLIAmount').html('≈' + convert(parseFloat(BigNumber(
                                amountEDLIAffiliate).toFixed(currencyInfo['round']))) + ' ' + currencyInfo['currency']
                            .toUpperCase());
                        form.find('.globalPageAffiliateProgramFormCalcOverdueEDLIAmount').html('≈' + convert(parseFloat(
                                BigNumber(amountEDLIAffiliate).multipliedBy(2).toFixed(currencyInfo['round']))) + ' ' +
                            currencyInfo['currency'].toUpperCase());
                        mask = form.find('.globalPageAffiliateProgramFormCalcLoansAmount').data('text-total');
                        form.find('.globalPageAffiliateProgramFormCalcLoansAmount').html(mask.replace('[amount]', '≈' +
                            convert(parseFloat(BigNumber(amountEDLIAffiliate).toFixed(currencyInfo['round']))) +
                            ' ' + currencyInfo['currency'].toUpperCase()));
                    } else {
                        //form.find('.globalAccountLoansNewFormTLI').removeClass('d-none');
                        form.find('.globalPageAffiliateProgramFormCalcReturn').removeClass('d-none');
                        days = parseInt(type.replace('d', ''));
                        amountEDLI = 0;
                        dailyRate = BigNumber(loanRate).dividedBy('365');
                        while (days > 0) {
                            dailyPercent = BigNumber(BigNumber(amount).plus(amountEDLI)).multipliedBy(dailyRate).toFixed(
                                12);
                            amountEDLI = BigNumber(amountEDLI).plus(dailyPercent).toFixed(12);
                            days = days - 1;
                        }
                        amountOverdueEDLI = BigNumber(amount).multipliedBy(BigNumber(loanRate2).dividedBy('365'));
                        amountEDLIAffiliate = BigNumber(amountEDLI).multipliedBy(currentAffiliatePercent).toFixed(
                            currencyInfo['round']);
                        amountOverdueEDLIAffiliate = BigNumber(BigNumber(amountOverdueEDLI).multipliedBy(2).multipliedBy(
                            currentAffiliatePercent)).toFixed(currencyInfo['round']);
                        form.find('.globalPageAffiliateProgramFormCalcReturnAmount').html(convert(parseFloat(BigNumber(
                                amountEDLIAffiliate).toFixed(currencyInfo['round']))) + ' ' + currencyInfo['currency']
                            .toUpperCase());
                        form.find('.globalPageAffiliateProgramFormCalcOverdueEDLIAmount').html('≈' + convert(parseFloat(
                            amountOverdueEDLIAffiliate)) + ' ' + currencyInfo['currency'].toUpperCase());
                        amountOverdueEDLIAffiliatePercent = BigNumber(BigNumber(amountEDLIAffiliate).dividedBy(amount))
                            .multipliedBy('100').toFixed(4);
                        form.find('.globalPageAffiliateProgramFormCalcReturnPercent').html(convert(parseFloat(
                            amountOverdueEDLIAffiliatePercent)) + '%');
                        mask = form.find('.globalPageAffiliateProgramFormCalcLoansAmount').data('text-total');
                        form.find('.globalPageAffiliateProgramFormCalcLoansAmount').html(mask.replace('[amount]', convert(
                                parseFloat(BigNumber(amountEDLIAffiliate).toFixed(currencyInfo['round']))) + ' ' +
                            currencyInfo['currency'].toUpperCase()));
                    }
                }

                amountPayment = BigNumber(amount).plus(amountEDLI);
                amountPaymentUsd = getUsdAmount(currency, amountPayment, 12);

                currentLtv = BigNumber(amountPaymentUsd).dividedBy(amountColUsd).toFixed(12);
                showLtv = 1000;
                if (BigNumber(amountColUsd).isLessThanOrEqualTo('0')) {
                    form.find('.globalPageAffiliateProgramFormCalcLTV').attr('style', 'color:#ef4444');
                    form.find('.globalPageAffiliateProgramFormCalcLTV').html('N/A');
                } else {
                    showLtv = BigNumber(currentLtv).multipliedBy('100').toFixed(4);
                    form.find('.globalPageAffiliateProgramFormCalcLTV').html(showLtv + '%');
                    if (BigNumber(currentLtv).isGreaterThan('0.8')) {
                        form.find('.globalPageAffiliateProgramFormCalcLTV').attr('style', 'color:#ef4444');
                    } else {
                        form.find('.globalPageAffiliateProgramFormCalcLTV').attr('style', 'color:rgb(22, 255, 142)');
                    }
                }
                if (BigNumber(currentAffiliatePercent).isGreaterThan(0)) {
                    form.find('.globalPageAffiliateProgramFormCalcLiquidationRewardPercent').html(convert(parseFloat(
                        BigNumber(5).multipliedBy(currentAffiliatePercent).toFixed(4))) + '%');
                } else {
                    form.find('.globalPageAffiliateProgramFormCalcLiquidationRewardPercent').html('0%');
                }
                if (BigNumber(amount).isGreaterThan(0) && BigNumber(amountCol).isGreaterThan(0) && BigNumber(showLtv)
                    .isLessThanOrEqualTo('80')) {
                    liqPrice = BigNumber(BigNumber(BigNumber(amount).plus(amountEDLI)).dividedBy(amountCol)).dividedBy(
                        '0.95');
                    form.find('.globalPageAffiliateProgramFormCalcLiquidation').html('1 ' + ' ' + currencyColInfo[
                            'currency'].toUpperCase() + '=' + BigNumber(liqPrice).toFixed(currencyInfo['round']) + ' ' +
                        currencyInfo['currency'].toUpperCase());
                    liqReward = BigNumber(BigNumber(amountCol).multipliedBy('0.05')).multipliedBy(currentAffiliatePercent);
                    form.find('.globalPageAffiliateProgramFormCalcLiquidationRewardAmount').html(convert(parseFloat(
                            BigNumber(liqReward).toFixed(currencyColInfo['round']))) + ' ' + currencyColInfo['currency']
                        .toUpperCase());
                } else {
                    form.find('.globalPageAffiliateProgramFormCalcLiquidation').html('N/A');
                    form.find('.globalPageAffiliateProgramFormCalcLiquidationRewardAmount').html('N/A');
                }
            }
        }

        function getFeeByPlanAndPercentKey(plan, percentId) {
            basicFee = 50;
            if (plan == 1) {
                basicFee = basicFee - (percentId * 4);
            } else {
                basicFee = basicFee - (percentId * 3);
                if (plan >= 4 && plan <= 9) {
                    basicFee = basicFee - (plan - 4);
                } else if (plan >= 10 && plan <= 15) {
                    basicFee = basicFee - (plan - 10);
                } else if (plan >= 16 && plan <= 21) {
                    basicFee = basicFee - ((plan - 16) * 1.5);
                }
            }
            return basicFee;
        }

        function getFeeByPlanAndPercentKeyOnlyPercentKey(plan, percentId) {
            basicFee = 0;
            if (plan == 1) {
                basicFee = basicFee - (percentId * 4);
            } else {
                basicFee = basicFee - (percentId * 3);
            }
            return basicFee;
        }

        function calcStakingAddForm(form) {
            amount = getAmount(form.find('input[name=amount]').val());
            count = 5;
            form.find('input[name=percent_id]').prop('checked', false);
            while (count >= 0) {
                el = form.find('input[name=percent_id]').eq(count);
                if (BigNumber(amount).isGreaterThanOrEqualTo(el.data('min'))) {
                    el.prop('checked', true);
                    count = 0;
                }
                count = count - 1;
            }
        }

        function calcStakingReleaseForm(form) {
            amount = getAmount(form.find('input[name=amount]').val());
            count = 5;
            form.find('input[name=percent_id]').prop('checked', false);
            while (count >= 0) {
                el = form.find('input[name=percent_id][value=' + count + ']');
                if (BigNumber(amount).isLessThanOrEqualTo(el.data('max')) && BigNumber(el.data('max')).isGreaterThan(0)) {
                    el.prop('checked', true);
                    count = 0;
                }
                count = count - 1;
            }
        }

