                monthlyPercent = BigNumber(percent).multipliedBy(30);
                monthlyReturnAmount = BigNumber(dailyReturnAmount).multipliedBy(30);
                yearlyPercent = BigNumber(percent).multipliedBy(365);
                yearlyReturnAmount = BigNumber(dailyReturnAmount).multipliedBy(365);

                monthlyPercentMin = BigNumber(percentMin).multipliedBy(30);
                monthlyReturnAmountMin = BigNumber(dailyReturnAmountMin).multipliedBy(30);
                yearlyPercentMin = BigNumber(percentMin).multipliedBy(365);
                yearlyReturnAmountMin = BigNumber(dailyReturnAmountMin).multipliedBy(365);

