                monthlyReturnAmount = BigNumber(monthlyReturnAmount).toFixed(currencyInfo['round']);
                yearlyReturnAmount = BigNumber(yearlyReturnAmount).toFixed(currencyInfo['round']);

                dailyReturnAmountMin = BigNumber(dailyReturnAmountMin).toFixed(currencyInfo['round']);
                monthlyReturnAmountMin = BigNumber(monthlyReturnAmountMin).toFixed(currencyInfo['round']);
                yearlyReturnAmountMin = BigNumber(yearlyReturnAmountMin).toFixed(currencyInfo['round']);

                form.find('.globalAccountStakingFormCalcEstDailyAmount').html('≈' + convert(parseFloat(dailyReturnAmount)) +
                    ' ' + currencyInfo['currency'].toUpperCase());
