        function initExchangeForm(form, toChanged = false) {
            amount = getAmount(form.find('input[name=amount]').val());
            currencyFrom = form.find('select[name=currency_from]').selectpicker('val');
            currencyTo = form.find('select[name=currency_to]').selectpicker('val');

            if (currencyFrom == currencyTo) {
                if (toChanged) {
                    firstItem = form.find('select[name=currency_from] option').not(':checked').first();
                    form.find('select[name=currency_from]').selectpicker('val', firstItem.attr('value'));
                    currencyFrom = firstItem.attr('value');
                } else {
                    firstItem = form.find('select[name=currency_to] option').not(':checked').first();
                    form.find('select[name=currency_to]').selectpicker('val', firstItem.attr('value'));
                    currencyTo = firstItem.attr('value');
                }
            }

            currencyInfoFrom = globalCurrencies[currencyFrom];
            currencyInfoTo = globalCurrencies[currencyTo];
            currentCurrencyFrom = currencyInfoFrom['currency'];
            currentCurrencyTo = currencyInfoTo['currency'];

            form.find('.inputAmountCurrency').html(currentCurrencyFrom.toUpperCase());
            form.find('.inputAmountCurrencyTo').html(currentCurrencyTo.toUpperCase());

            form.find('[data-module=user-balance]').addClass('d-none');
            form.find('[data-module=user-balance][data-currency=' + currencyFrom + ']').removeClass('d-none');

            res = calcExchangeAmount(currencyFrom, currencyTo, amount);
            if (res) {
                form.find('.globalAccountExchangeFormReceive').html('~' + res.pay_amount);
                form.find('.globalAccountExchangeFormFee').html(res.total_fee + ' ' + currentCurrencyFrom.toUpperCase());
                form.find('.globalAccountExchangeFormRate').html('<strong>1</strong> ' + currentCurrencyFrom.toUpperCase() +
                    ' = <strong>' + res.rate + '</strong> ' + currentCurrencyTo.toUpperCase());
            } else {
                form.find('.globalAccountExchangeFormReceive').html($('.globalAccountExchangeFormRate').data(
                    'loading-text'));
                form.find('.globalAccountExchangeFormFee').html($('.globalAccountExchangeFormRate').data('loading-text'));
                form.find('.globalAccountExchangeFormRate').html($('.globalAccountExchangeFormRate').data('loading-text'));
            }

        }

        function calcExchangeAmount(currencyFrom, currencyTo, amount) {
            if (exchangePrices) {
                currencyFromInfo = globalCurrencies[currencyFrom];
                currencyToInfo = globalCurrencies[currencyTo];
                if (currencyFromInfo['currency'] == 'usdt' || currencyToInfo['currency'] == 'usdt') {
                    if (currencyFromInfo['currency'] == 'usdt')
                        symbol = currencyToInfo['binance_ticker'];
                    else
                        symbol = currencyFromInfo['binance_ticker'];
                    if (BigNumber(exchangePrices[symbol]).isGreaterThan(0)) {
                        rate = BigNumber(exchangePrices[symbol]).toFixed(12);
                        if (currencyFromInfo['currency'] == 'usdt') {
                            resAmountBeforeFee = BigNumber(amount).dividedBy(rate).toFixed(12);
                            rateForOne = BigNumber(BigNumber(1).dividedBy(rate)).toFixed(currencyToInfo['round']);
                        } else {
                            resAmountBeforeFee = BigNumber(amount).multipliedBy(rate).toFixed(12);
                            rateForOne = BigNumber(rate).toFixed(currencyToInfo['round']);
                        }
                        resAmount = BigNumber(resAmountBeforeFee).multipliedBy('0.99').toFixed(currencyToInfo['round']);
                        feeAmount = BigNumber(amount).multipliedBy('0.01').toFixed(currencyFromInfo['round'])
                        return {
                            'pay_amount': parseFloat(resAmount),
                            'total_fee': parseFloat(feeAmount),
                            'rate': parseFloat(rateForOne)
                        };
                    }

                } else {
                    symbolFrom = currencyFromInfo['binance_ticker'];
                    symbolTo = currencyToInfo['binance_ticker']
                    if (BigNumber(exchangePrices[symbolFrom]).isGreaterThan(0) && BigNumber(exchangePrices[symbolTo])
                        .isGreaterThan(0)) {
                        amountFromToUsdt = BigNumber(amount).multipliedBy(exchangePrices[symbolFrom]).toFixed(12);
                        resAmountBeforeFee = BigNumber(amountFromToUsdt).dividedBy(exchangePrices[symbolTo]).toFixed(12);
                        resAmount = BigNumber(resAmountBeforeFee).multipliedBy('0.99').toFixed(currencyToInfo['round']);

                        amountFromToUsdtForOne = BigNumber(1).multipliedBy(exchangePrices[symbolFrom]).toFixed(12);
                        rateForOne = BigNumber(amountFromToUsdtForOne).dividedBy(exchangePrices[symbolTo]).toFixed(
                            currencyToInfo['round']);


                        feeAmount = BigNumber(amount).multipliedBy('0.01').toFixed(currencyFromInfo['round'])
                        return {
                            'pay_amount': parseFloat(resAmount),
                            'total_fee': parseFloat(feeAmount),
                            'rate': parseFloat(rateForOne)
                        };
                    }

                }
            }
        }

        function initLoanForm(form, newCurrency = null, newType = null) {
            currency = form.find('select[name=currency]').selectpicker('val');
            currencyCol = form.find('select[name=currency_col]').selectpicker('val');
            if (newCurrency) {
                form.find('select[name=currency]').selectpicker('val', newCurrency);
                changeAmount(form);
                form.find('input[name=old_currency]').val(newCurrency);
                currencyCol = form.find('select[name=currency_col]').selectpicker('val');
                form.find('select[name=currency_col] option').prop('disabled', false);
                if (currencyCol == newCurrency) {
                    firstItem = form.find('select[name=currency_col] option').not(':checked').first();
                    form.find('select[name=currency_col]').selectpicker('val', firstItem.attr('value'));
                    changeAmount(form, 'amount_col', 'old_currency_col', 'currency_col');
                    form.find('input[name=old_currency_col]').val(newCurrency);
                    currencyCol = form.find('select[name=currency_col]').selectpicker('val');
                }
                form.find('select[name=currency_col] option[value=' + newCurrency + ']').prop('disabled', true);
                form.find('select[name=currency_col]').selectpicker('destroy');
                form.find('select[name=currency_col]').selectpicker('render');
                currency = form.find('select[name=currency]').selectpicker('val');
                currencyCol = form.find('select[name=currency_col]').selectpicker('val');
                amount = getAmount(form.find('input[name=amount]').val());
                currencyColInfo = globalCurrencies[currencyCol];
                amountUsd = getUsdAmount(currency, amount, 2);
                rate = globalRates[currencyColInfo['currency']];
                newColAmount = BigNumber(BigNumber(amountUsd).multipliedBy('2')).dividedBy(rate).toFixed(currencyColInfo[
                    'round']);
                form.find('input[name=amount_col]').val(convert(parseFloat(BigNumber(newColAmount).toFixed(currencyColInfo[
                    'round']))));
            }
            currencyInfo = globalCurrencies[currency];
            globalLoanRatesCurrency = globalLoanRates[currencyInfo['currency']];
            loanTypes = ['7d', '14d', '30d', '60d', '90d', '180d', 'flexible'];
            checked = false;
            if (newType || newCurrency) {
                form.find('input[name=type]').prop('checked', false);
                checked = false;
                $.each(loanTypes, function(index, value) {
                    loanTypeRadio = form.find('input[name=type][value="' + value + '"]');
                    loanTypeRadioItem = loanTypeRadio.closest('.duration-radio-item-wrapper');
                    if (BigNumber(globalLoanRatesCurrency[value]).isGreaterThan(0)) {
                        rate = BigNumber(globalLoanRatesCurrency[value]).multipliedBy('100').toFixed(2);
                        loanTypeRadioItem.find('.min-term-radio__fee').html(rate + '%');
                        loanTypeRadioItem.removeClass('d-none');
                        if (newType && newType == value) {
                            loanTypeRadio.prop('checked', true);
                        } else if (!newType && !checked) {
                            loanTypeRadio.prop('checked', true);
                            checked = true;
                        }
                    } else {
                        loanTypeRadioItem.addClass('d-none');
                    }
                });
            }

            currencyInfo = globalCurrencies[currency];
            currencyInfoCol = globalCurrencies[currencyCol];
            currentCurrency = currencyInfo['currency'];
            currentCurrencyCol = currencyInfoCol['currency'];

            form.find('.inputAmountCurrency').html(currentCurrency.toUpperCase());
            form.find('.inputAmountCurrencyCol').html(currentCurrencyCol.toUpperCase());

            form.find('[data-module=user-balance]').addClass('d-none');
            form.find('[data-module=user-balance][data-currency=' + currencyCol + ']').removeClass('d-none');

            calcLoanForm(form);
        }

        function calcLoanForm(form, newColCurrency = null) {
            if (newColCurrency) {
                changeAmount(form, 'amount_col', 'old_currency_col', 'currency_col');
                form.find('input[name=old_currency_col]').val(newColCurrency);
            }
            amount = getAmount(form.find('input[name=amount]').val());
            amountCol = getAmount(form.find('input[name=amount_col]').val());
            type = form.find('input[name=type]:checked').val();
            currency = form.find('select[name=currency]').selectpicker('val');
            currencyInfo = globalCurrencies[currency];
            currencyCol = form.find('select[name=currency_col]').selectpicker('val');
            currencyColInfo = globalCurrencies[currencyCol];
            form.find('.optimaDepositButton').data('currency', currencyCol);
            amountColUsd = getUsdAmount(currencyCol, amountCol, 12);
            loanRate = globalLoanRates[currency][type];
            loanAPR = BigNumber(loanRate).multipliedBy('100').toFixed(2);
            form.find('.globalAccountLoansNewFormAPR').html(loanAPR + '% APR');
            amountEDLI = 0;
            if (type == 'flexible') {
                form.find('.globalAccountLoansNewFormTLI').addClass('d-none');
                form.find('.globalAccountLoansNewFormEDLI').removeClass('d-none');
                amountEDLI = BigNumber(amount).multipliedBy(BigNumber(loanRate).dividedBy('365')).toFixed(currencyInfo[
                    'round']);
                form.find('.globalAccountLoansNewFormEDLIAmount').html('≈' + convert(parseFloat(BigNumber(amountEDLI)
                    .toFixed(currencyInfo['round']))) + ' ' + currencyInfo['currency'].toUpperCase())
            } else {
                form.find('.globalAccountLoansNewFormTLI').removeClass('d-none');
                form.find('.globalAccountLoansNewFormEDLI').addClass('d-none');
                days = parseInt(type.replace('d', ''));
                amountEDLI = 0;
                dailyRate = BigNumber(loanRate).dividedBy('365');
                while (days > 0) {
                    dailyPercent = BigNumber(BigNumber(amount).plus(amountEDLI)).multipliedBy(dailyRate).toFixed(12);
                    amountEDLI = BigNumber(amountEDLI).plus(dailyPercent).toFixed(12);
                    days = days - 1;
                }
                form.find('.globalAccountLoansNewFormTLIAmount').html(convert(parseFloat(BigNumber(amountEDLI).toFixed(
                    currencyInfo['round']))) + ' ' + currencyInfo['currency'].toUpperCase())
            }

            amountPayment = BigNumber(amount).plus(amountEDLI);
            amountPaymentUsd = getUsdAmount(currency, amountPayment, 12);

            currentLtv = BigNumber(amountPaymentUsd).dividedBy(amountColUsd).toFixed(12);
            showLtv = 1000;
            if (BigNumber(amountColUsd).isLessThanOrEqualTo('0')) {
                form.find('.globalAccountLoansNewFormLTV').attr('style', 'color:#ef4444');
                form.find('.globalAccountLoansNewFormLTV').html('N/A');
            } else {
                showLtv = BigNumber(currentLtv).multipliedBy('100').toFixed(4);
                form.find('.globalAccountLoansNewFormLTV').html(showLtv + '%');
                if (BigNumber(currentLtv).isGreaterThan('0.8')) {
                    form.find('.globalAccountLoansNewFormLTV').attr('style', 'color:#ef4444');
                } else {
                    form.find('.globalAccountLoansNewFormLTV').attr('style', 'color:rgb(22, 255, 142)');
                }
            }

            if (BigNumber(amount).isGreaterThan(0) && BigNumber(amountCol).isGreaterThan(0) && BigNumber(showLtv)
                .isLessThanOrEqualTo('80')) {
                liqPrice = BigNumber(BigNumber(BigNumber(amount).plus(amountEDLI)).dividedBy(amountCol)).dividedBy('0.95');
                form.find('.globalAccountLoansNewFormLiquidation').html('1 ' + ' ' + currencyColInfo['currency']
                    .toUpperCase() + '=' + BigNumber(liqPrice).toFixed(currencyInfo['round']) + ' ' + currencyInfo[
                        'currency'].toUpperCase());

            } else {
                form.find('.globalAccountLoansNewFormLiquidation').html('N/A');
            }
        }

