        function searchFAQSection(search) {
            search = $.trim(search.toLowerCase());
            selectFAQSection('', true);
            if (search) {
                $('.globalPageFAQResultsItemsItem').each(function() {
                    el = $(this);
                    itemTitle = $.trim(el.find('.help-article-item__title').text().toLowerCase());
                    itemText = $.trim(el.find('.help-article-item__descr').text().toLowerCase());
                    if (itemTitle.indexOf(search) < 0 && itemText.indexOf(search) < 0) {
                        el.addClass('d-none');
                    }
                })
                $('.front-help-menu-item').addClass('d-none');
            } else {
                $('.front-help-menu-item').removeClass('d-none');
            }
        }

