                                'placeholder': value2
                            };
                            countriesByPlaceholder.push(newElement);
                        })
                    }
                })
                countriesByPlaceholder.sort(function(a, b) {
                    return b.placeholder.length - a.placeholder.length
                });

                $('.authPhone').each(function(indexAuthPhone) {
                    el = $(this);
                    $(this).on('keyup', function() {
                        currentPhone = $(this).val();
                        randomKey = randomIntFromInterval(1, 99999999);
                        counts[randomKey] = 0;
                        currentSuccessCountry = false;
                        if (
                            (userSelectedCountryCodeLogin && indexAuthPhone == 0) ||
                            (userSelectedCountryCodeSignUp && indexAuthPhone == 1)
                        ) {
                            $.each(globalCountries, function(index, value) {
                                if (
                                    (userSelectedCountryCodeLogin == value.code &&
                                        indexAuthPhone == 0) ||
                                    (userSelectedCountryCodeSignUp == value.code &&
                                        indexAuthPhone == 1)
                                ) {
                                    if (value.masks_placeholder) {
                                        $.each(JSON.parse(value.masks_placeholder),
                                            function(index2, value2) {
                                                if (currentPhone.indexOf(value2) ===
                                                    0) {
                                                    currentSuccessCountry = true;
                                                }
                                            })
                                    }
                                }
                            })
                        }
                        if (currentSuccessCountry)
                            return false;

                        $.each(countriesByPlaceholder, function(index, value) {
                            if (currentPhone.indexOf(value.placeholder) === 0) {
                                changeForSecond = true;
                                $('.authPhone:eq(' + indexAuthPhone + ')').closest('form')
                                    .find('select[name=country_phone]').selectpicker('val',
                                        value.code);
                                if (indexAuthPhone == 0)
                                    userSelectedCountryCodeLogin = value.code;
                                if (indexAuthPhone == 1)
                                    userSelectedCountryCodeSignUp = value.code;
                                counts[randomKey]++;
                                return false;
                            }
                        })
                    });
                })
            }
