                if (planInfo['return_any_time_array'][0]['min_seconds'] > 0) {
                    days = planInfo['return_any_time_array'][0]['min_seconds'] / 86400;
                    mask = modal.find('.modalStakingAddWarning').find('.system-message__text').data('text');
                    mask = mask.replace('[days]', days);
