                    modal.find('.modalStakingAddWarning').removeClass('d-none');
                }
                $.each(JSON.parse($(this).data('percents')), function(index, value) {
                    if (index >= percentId) {
                        addAmount = BigNumber(value['min_max']['min_' + currentCurrency]).minus(
