            $('.optimaStakingReleaseButton').on('click', function() {
                modal = $('#modalStakingRelease');
                beforeSubmitForm(modal.find('form'), true);
                form = modal.find('form');
                currentCurrency = $(this).data('currency');
                form.data('currency', currentCurrency);
                currencyInfo = globalCurrencies[currentCurrency];
                modal.find('.currency-icon').attr('class', 'currency-icon');
                modal.find('.currency-icon').addClass('currency-icon--' + currencyInfo['config']['data'][
                    'icon'
                ]);
                currencyIconSrc = modal.find('.currency-icon img').data('src');
                modal.find('.currency-icon img').attr('src', currencyIconSrc.replace('[icon]', currencyInfo[
                    'config']['data']['icon']));
                modal.find('input[name=id]').val($(this).data('id'));
                modal.find('.optimaDepositButton').data('currency', currentCurrency);

                initStakingReleaseForm(form, $(this).data('currency'));
                form.find('input[name=percent_id]').prop('checked', false);
                form.find('.modalStakingReleaseFormFeesItemsItem').addClass('d-none');
                form.find('.modalStakingReleaseFormFeesItemsItemActiveFee').addClass('d-none');
                form.find('.modalStakingReleaseFormFeesItemsItemNewFee').addClass('d-none');
                percentId = $(this).data('percent-id');
                amount = $(this).data('amount');
                plan = $(this).data('plan');
                percents = JSON.parse($(this).data('percents'));
                percentsArray = [];
                $.each(percents, function(index, value) {
                    percentsArray.push(value);
                });
                lastIndex = null;
                $.each(percents, function(index, value) {
                    if (index <= percentId) {
                        eqItem = form.find('input[name=percent_id][value=' + index + ']').closest(
                            '.modalStakingReleaseFormFeesItemsItem');
                        upToText = form.find('input[name=percent_id][value=' + index + ']').data(
                            'up-to-text');
                        noChangeText = form.find('input[name=percent_id][value=' + index + ']')
                            .data('no-change-text');
                        if (lastIndex === null) {
                            releaseAmount = BigNumber(amount);
                        } else {
                            releaseAmount = BigNumber(amount).minus(percents[lastIndex]['min_max'][
                                'min_' + currentCurrency
                            ]);
                        }
                        eqItem.find('input[name=percent_id]').data('max', 0);
                        if (BigNumber(releaseAmount).isGreaterThan(0) > 0 || index == percentId) {
                            eqItem.find('.form-commission-radio__amount').html(upToText + ' ' +
                                releaseAmount + ' ' + currentCurrency.toUpperCase());
                            eqItem.find('input[name=percent_id]').data('max', releaseAmount);
                            newFee = getFeeByPlanAndPercentKeyOnlyPercentKey(plan, index);
                            if (newFee) {
                                mask = eqItem.find('.modalStakingReleaseFormFeesItemsItemNewFee')
                                    .data('fee-text');
                                eqItem.find('.modalStakingReleaseFormFeesItemsItemNewFee').html(mask
                                    .replace('[fee]', newFee));
                                eqItem.find('.modalStakingReleaseFormFeesItemsItemNewFee')
                                    .removeClass('d-none');
                            }
                            if (index == percentId) {
                                eqItem.find('input[name=percent_id]').prop('checked', true);
                                eqItem.find('.modalStakingReleaseFormFeesItemsItemActiveFee')
                                    .removeClass('d-none');
                                if (BigNumber(releaseAmount).isLessThan(0)) {
                                    eqItem.find('.form-commission-radio__amount').html(
                                        noChangeText);
                                }
                            }
                            lastIndex = index + 1;
                            eqItem.removeClass('d-none');
                        }
                    }
                })
                modal.modal('show');
            })

